  1→/**
  2→ * BookSage Live — ADK-based server with Runner.runAsync.
  3→ *
  4→ * ADK TS v0.5 does not have runLive() (Python ADK feature).
  5→ * We use the @google/genai Live API for the WebSocket streaming connection
  6→ * and the ADK Runner for turn-by-turn tool execution when needed.
  7→ */
  8→
  9→import express from "express";
 10→import { createServer } from "http";
 11→import path from "path";
 12→import { WebSocketServer, WebSocket } from "ws";
 13→import { GoogleGenAI, Type } from "@google/genai";
 14→import { v4 as uuidv4 } from "crypto";
 15→import type { IncomingMessage } from "http";
 16→import {
 17→  Runner,
 18→  InMemorySessionService,
 19→  LiveRequestQueue,
 20→} from "@google/adk";
 21→import { rootAgent, getRunConfig, LIVE_MODEL } from "./adk-agent.js";
 22→
 23→const APP_NAME = "booksage-live";
 24→const STATIC_DIR = path.join(__dirname, "..", "..", "static");
 25→
 26→const sessionService = new InMemorySessionService();
 27→
 28→function createRunner(): Runner {
 29→  return new Runner({
 30→    appName: APP_NAME,
 31→    agent: rootAgent,
 32→    sessionService,
 33→  });
 34→}
 35→
 36→// =========================================================================
 37→// Express + WebSocket server
 38→// =========================================================================
 39→
 40→export function createApp() {
 41→  const app = express();
 42→  const server = createServer(app);
 43→  const wss = new WebSocketServer({ noServer: true });
 44→
 45→  app.get("/health", (_req, res) => {
 46→    res.json({
 47→      status: "ok",
 48→      app: APP_NAME,
 49→      engine: "adk",
 50→      agent: rootAgent.name,
 51→      sub_agents: (rootAgent as any).subAgents?.map((a: any) => a.name) ?? [],
 52→    });
 53→  });
 54→
 55→  app.get("/", (_req, res) => {
 56→    res.sendFile(path.join(STATIC_DIR, "index.html"));
 57→  });
 58→
 59→  app.use("/static", express.static(STATIC_DIR));
 60→
 61→  server.on("upgrade", (request: IncomingMessage, socket, head) => {
 62→    const url = new URL(request.url ?? "/", `http://${request.headers.host}`);
 63→    if (url.pathname === "/ws/read") {
 64→      wss.handleUpgrade(request, socket, head, (ws) => {
 65→        wss.emit("connection", ws, request);
 66→      });
 67→    } else {
 68→      socket.destroy();
 69→    }
 70→  });
 71→
 72→  wss.on("connection", (ws: WebSocket) => {
 73→    handleWebSocket(ws);
 74→  });
 75→
 76→  return server;
 77→}
 78→
 79→async function handleWebSocket(ws: WebSocket) {
 80→  const apiKey =
 81→    process.env.GOOGLE_API_KEY ?? process.env.GEMINI_API_KEY;
 82→  if (!apiKey) {
 83→    ws.send(JSON.stringify({ type: "error", message: "No API key configured" }));
 84→    ws.close();
 85→    return;
 86→  }
 87→
 88→  process.env.GOOGLE_API_KEY = apiKey;
 89→
 90→  const client = new GoogleGenAI({ apiKey });
 91→  const runConfig = getRunConfig();
 92→
 93→  const userId = `user-${randomHex(8)}`;
 94→  const sessionId = `session-${randomHex(8)}`;
 95→
 96→  let frameCount = 0;
 97→  let firstFrameSeeded = false;
 98→  let closed = false;
 99→
100→  console.log(`[${APP_NAME}] Client connected, user=${userId}, session=${sessionId}`);
101→
102→  // Build the Gemini Live config from runConfig
103→  const liveConfig: any = {
104→    response_modalities: ["AUDIO"],
105→    system_instruction: (rootAgent as any).instruction,
106→    speech_config: {
107→      voice_config: {
108→        prebuilt_voice_config: { voice_name: "Kore" },
109→      },
110→    },
111→    input_audio_transcription: {},
112→    output_audio_transcription: {},
113→    realtime_input_config: {
114→      automatic_activity_detection: {
115→        disabled: false,
116→        start_of_speech_sensitivity: "START_SENSITIVITY_HIGH",
117→        end_of_speech_sensitivity: "END_SENSITIVITY_HIGH",
118→        prefix_padding_ms: 200,
119→        silence_duration_ms: 1500,
120→      },
121→    },
122→    // Declare tools for the Live session so Gemini can call them
123→    tools: buildToolDeclarations(),
124→  };
125→
126→  try {
127→    const session = await client.live.connect({
128→      model: LIVE_MODEL,
129→      config: liveConfig,
130→    });
131→
132→    const receiveFromClient = async () => {
133→      try {
134→        for await (const rawMsg of wsMessages(ws)) {
135→          if (closed) break;
136→
137→          if (rawMsg instanceof Buffer || rawMsg instanceof ArrayBuffer) {
138→            const data =
139→              rawMsg instanceof ArrayBuffer
140→                ? new Uint8Array(rawMsg)
141→                : rawMsg;
142→            await session.sendRealtimeInput({
143→              audio: {
144→                data: Buffer.from(data).toString("base64"),
145→                mimeType: "audio/pcm;rate=16000",
146→              },
147→            });
148→          } else if (typeof rawMsg === "string") {
149→            const data = JSON.parse(rawMsg);
150→            const msgType = data.type;
151→
152→            if (msgType === "camera") {
153→              const imgBytes = Buffer.from(data.data, "base64");
154→              const mime = data.mime_type ?? "image/jpeg";
155→              await session.sendRealtimeInput({
156→                media: {
157→                  data: imgBytes.toString("base64"),
158→                  mimeType: mime,
159→                },
160→              });
161→              frameCount++;
162→
163→              if (!firstFrameSeeded && frameCount >= 3) {
164→                firstFrameSeeded = true;
165→                await session.sendClientContent({
166→                  turns: {
167→                    role: "user",
168→                    parts: [
169→                      {
170→                        text:
171→                          "[GREET] You just received the first camera " +
172→                          "frame showing a book page. Read the visible text " +
173→                          "and give a brief, specific greeting. Mention what " +
174→                          "you see (title, author, topic, language, difficulty). " +
175→                          "Keep it to 2 sentences. Be warm.",
176→                      },
177→                    ],
178→                  },
179→                  turnComplete: true,
180→                });
181→                console.log(`[${APP_NAME}] Context seed sent (frame #${frameCount})`);
182→              }
183→            } else if (msgType === "set_mode") {
184→              const modeMap: Record<string, string> = {
185→                vocabulary: "Switch to Lexicon — I want vocabulary help.",
186→                literary: "Switch to Sage — let's discuss themes and meaning.",
187→                study: "Switch to Tutor — I want study help and quizzes.",
188→              };
189→              const mode = data.mode ?? "vocabulary";
190→              const text = modeMap[mode] ?? modeMap.vocabulary;
191→              await session.sendClientContent({
192→                turns: {
193→                  role: "user",
194→                  parts: [{ text }],
195→                },
196→                turnComplete: true,
197→              });
198→              const nameMap: Record<string, string> = {
199→                vocabulary: "Lexicon",
200→                literary: "Sage",
201→                study: "Tutor",
202→              };
203→              ws.send(
204→                JSON.stringify({
205→                  type: "mode_changed",
206→                  mode,
207→                  name: nameMap[mode] ?? mode,
208→                })
209→              );
210→            } else if (msgType === "text") {
211→              await session.sendClientContent({
212→                turns: {
213→                  role: "user",
214→                  parts: [{ text: data.text }],
215→                },
216→                turnComplete: true,
217→              });
218→            }
219→          }
220→        }
221→      } catch (e: any) {
222→        if (!closed) console.log(`[${APP_NAME}] receive error:`, e?.message);
223→      }
224→    };
225→
226→    const sendToClient = async () => {
227→      try {
228→        const turn = session.receive();
229→        for await (const response of turn) {
230→          if (closed) break;
231→
232→          // Audio data
233→          if (response.data) {
234→            ws.send(response.data, { binary: true });
235→          }
236→
237→          // Text transcript
238→          if (response.text) {
239→            ws.send(
240→              JSON.stringify({
241→                type: "transcript",
242→                role: "agent",
243→                text: response.text,
244→              })
245→            );
246→          }
247→
248→          // User speech transcription
249→          if (
250→            response.serverContent &&
251→            (response.serverContent as any).inputTranscription
252→          ) {
253→            const userText = (response.serverContent as any).inputTranscription;
254→            if (userText?.text) {
255→              ws.send(
256→                JSON.stringify({
257→                  type: "transcript",
258→                  role: "user",
259→                  text: userText.text,
260→                })
261→              );
262→            }
263→          }
264→
265→          // Function calls from model
266→          if (response.toolCall) {
267→            for (const fc of response.toolCall.functionCalls ?? []) {
268→              ws.send(
269→                JSON.stringify({
270→                  type: "tool_call",
271→                  name: fc.name,
272→                  args: fc.args ?? {},
273→                })
274→              );
275→
276→              // Execute tool locally and send response back
277→              const result = executeToolLocally(fc.name!, fc.args ?? {});
278→              ws.send(
279→                JSON.stringify({
280→                  type: "tool_result",
281→                  name: fc.name,
282→                  result,
283→                })
284→              );
285→
286→              // Send function response back to Gemini
287→              await session.sendToolResponse({
288→                functionResponses: [
289→                  {
290→                    name: fc.name!,
291→                    response: result,
292→                    id: fc.id,
293→                  },
294→                ],
295→              });
296→            }
297→          }
298→
299→          // Turn complete
300→          if (
301→            response.serverContent &&
302→            (response.serverContent as any).turnComplete
303→          ) {
304→            ws.send(JSON.stringify({ type: "turn_complete" }));
305→          }
306→        }
307→      } catch (e: any) {
308→        if (!closed && !String(e).toLowerCase().includes("close")) {
309→          console.log(`[${APP_NAME}] send error:`, e?.message);
310→        }
311→      }
312→    };
313→
314→    await Promise.all([receiveFromClient(), sendToClient()]);
315→    closed = true;
316→  } catch (e: any) {
317→    console.error(`[${APP_NAME}] WebSocket error:`, e);
318→    try {
319→      ws.send(JSON.stringify({ type: "error", message: String(e) }));
320→    } catch {}
321→  } finally {
322→    console.log(`[${APP_NAME}] Client disconnected (frames=${frameCount})`);
323→    try {
324→      ws.close();
325→    } catch {}
326→  }
327→}
