/**
 * BookSage Live — ADK multi-agent with tools and session state.
 * Root agent routes between 3 persona sub-agents via AutoFlow.
 * Each sub-agent has specialized tools for its reading mode.
 */

import { readFileSync } from "fs";
import path from "path";
import { z } from "zod";
import { LlmAgent, FunctionTool, Context } from "@google/adk";
import type { RunConfig } from "@google/adk";

// =========================================================================
// Model — native audio for voice + vision
// =========================================================================

export const LIVE_MODEL = "gemini-2.5-flash-preview-native-audio-dialog";

// =========================================================================
// CEFR word difficulty data
// =========================================================================

const CEFR_DATA_PATH = path.join(__dirname, "data", "cefr_b2_c1_light.json");
let B2_WORDS: Set<string> | null = null;
let C1_WORDS: Set<string> | null = null;

function loadCefr() {
  if (B2_WORDS) return;
  try {
    const raw = readFileSync(CEFR_DATA_PATH, "utf-8");
    const data = JSON.parse(raw);
    B2_WORDS = new Set(data.B2 ?? []);
    C1_WORDS = new Set(data.C1 ?? []);
  } catch {
    B2_WORDS = new Set();
    C1_WORDS = new Set();
  }
}

// =========================================================================
// Tool implementations
// =========================================================================

const defineWordTool = new FunctionTool({
  name: "define_word",
  description: "Define a word in its reading context.",
  parameters: z.object({
    word: z.string().describe("The word to define."),
    context: z.string().describe("The sentence or passage where the word appears."),
  }),
  execute: (input, toolContext) => {
    loadCefr();
    const wl = input.word.toLowerCase();
    const level = C1_WORDS!.has(wl) ? "C1" : B2_WORDS!.has(wl) ? "B2" : null;

    if (toolContext) {
      const concepts: string[] = toolContext.state.get("concepts", []) as string[];
      if (!concepts.includes(input.word)) {
        concepts.push(input.word);
        toolContext.state.set("concepts", concepts.slice(-30));
      }
    }

    return {
      word: input.word,
      context: input.context,
      cefr_level: level,
      instruction:
        `Define '${input.word}' in the context: '${input.context}'. ` +
        (level ? `This is a ${level}-level word. ` : "") +
        "Give the definition, usage example, and etymology if interesting.",
    };
  },
});

const flagDifficultWordsTool = new FunctionTool({
  name: "flag_difficult_words",
  description: "Identify difficult words on the visible page.",
  parameters: z.object({
    page_text: z.string().describe("The text visible on the book page."),
  }),
  execute: (input) => {
    loadCefr();
    const words = new Set(input.page_text.toLowerCase().split(/\s+/));
    const flagged: Array<{ word: string; level: string; label: string }> = [];
    for (const w of words) {
      const clean = w.replace(/^[.,;:!?"'()\[\]]+|[.,;:!?"'()\[\]]+$/g, "");
      if (C1_WORDS!.has(clean)) {
        flagged.push({ word: clean, level: "C1", label: "Advanced" });
      } else if (B2_WORDS!.has(clean)) {
        flagged.push({ word: clean, level: "B2", label: "Challenging" });
      }
    }
    return {
      flagged_count: flagged.length,
      words: flagged.slice(0, 10),
      instruction:
        "Mention 2-3 of the most interesting difficult words you found. " +
        "Offer to explain them.",
    };
  },
});

const trackConceptTool = new FunctionTool({
  name: "track_concept",
  description: "Track a key concept discussed during the reading session.",
  parameters: z.object({
    concept: z.string().describe("The concept or theme to remember."),
    page_context: z.string().describe("Brief context of where/how it appeared."),
  }),
  execute: (input, toolContext) => {
    if (toolContext) {
      const concepts: string[] = toolContext.state.get("concepts", []) as string[];
      if (!concepts.includes(input.concept)) {
        concepts.push(input.concept);
        toolContext.state.set("concepts", concepts.slice(-30));
      }
      const pages: string[] = toolContext.state.get("page_notes", []) as string[];
      pages.push(`${input.concept}: ${input.page_context}`);
      toolContext.state.set("page_notes", pages.slice(-20));
    }
    const conceptCount = toolContext
      ? (toolContext.state.get("concepts", []) as string[]).length
      : 0;
    return {
      tracked: input.concept,
      total_concepts: conceptCount,
      instruction: "Concept noted. Continue the conversation naturally.",
    };
  },
});

const getSessionSummaryTool = new FunctionTool({
  name: "get_session_summary",
  description: "Get a summary of everything discussed in this reading session.",
  parameters: z.object({}),
  execute: (_input, toolContext) => {
    const concepts: string[] = (toolContext?.state.get("concepts", []) ?? []) as string[];
    const pages: string[] = (toolContext?.state.get("page_notes", []) ?? []) as string[];
    const uniquePages =
      pages.length > 0 ? new Set(pages.map((n) => n.split(":")[0])).size : 0;
    return {
      concepts_discussed: concepts,
      page_notes: pages,
      total_concepts: concepts.length,
      total_pages: uniquePages,
      instruction:
        "Summarize what was covered in this reading session. " +
        "Highlight key concepts and connections between pages.",
    };
  },
});

const analyzePassageTool = new FunctionTool({
  name: "analyze_passage",
  description: "Analyze a literary passage for themes, devices, or structure.",
  parameters: z.object({
    passage: z.string().describe("The text passage to analyze."),
    analysis_type: z.string().describe(
      "Type of analysis: 'theme', 'device', 'structure', 'character', 'argument'."
    ),
  }),
  execute: (input, toolContext) => {
    const concepts: string[] = (toolContext?.state.get("concepts", []) ?? []) as string[];
    return {
      passage_excerpt: input.passage.slice(0, 200),
      analysis_type: input.analysis_type,
      prior_concepts: concepts.slice(-5),
      instruction:
        `Analyze this passage for ${input.analysis_type}. ` +
        "Connect to previously discussed concepts if relevant. " +
        "Keep analysis to 2-3 sentences.",
    };
  },
});

const quizComprehensionTool = new FunctionTool({
  name: "quiz_comprehension",
  description: "Generate a comprehension question about the current reading.",
  parameters: z.object({
    topic: z.string().describe("What to quiz about."),
    difficulty: z.string().describe(
      "Question difficulty: 'recall', 'analysis', 'synthesis'."
    ),
  }),
  execute: (input) => {
    return {
      topic: input.topic,
      difficulty: input.difficulty,
      instruction:
        `Ask a ${input.difficulty}-level question about ${input.topic}. ` +
        "Use Socratic method — guide, don't lecture. " +
        "If the reader answers, celebrate correct answers and gently redirect mistakes.",
    };
  },
});

// =========================================================================
// Base instruction — shared across all agents
// =========================================================================

const BASE_INSTRUCTION = `\
You are BookSage, an AI reading companion. The user points their camera at \
book pages and you discuss the content via real-time voice conversation.

CORE RULES:
- You SEE book pages through the camera. Read and understand the visible text.
- Work with ANY language — detect and adapt automatically.
- 5-15 seconds of speech MAX. 2-3 sentences. Don't lecture.
- If the user is silently reading, stay quiet unless asked.
- If interrupted, stop immediately.
- NEVER say "as an AI" or "as a language model."
- Use your tools to track concepts and provide structured analysis.

CROSS-PAGE MEMORY:
You have tools to track concepts across pages. Use track_concept for important \
themes, characters, and ideas. When you see connections to earlier pages, \
mention them naturally: "This connects to what we discussed earlier..."

When you receive the first camera frame, observe the page and give a brief, \
specific greeting — mention what you see (title, author, topic, language, \
difficulty level). Keep it to 2 sentences.
`;

// =========================================================================
// Sub-agent definitions
// =========================================================================

export const lexiconAgent = new LlmAgent({
  name: "lexicon",
  model: LIVE_MODEL,
  instruction:
    BASE_INSTRUCTION +
    `
YOUR PERSONA: LEXICON (Vocabulary Guide)
Personality: Patient, precise, loves words. Gets excited about etymology.

Use define_word for specific word lookups. Use flag_difficult_words proactively \
to notice challenging vocabulary on the page. Use track_concept to remember \
words discussed.

Style:
- Define words in context, provide etymology when interesting
- For foreign language texts: pronunciation tips, literal vs contextual meaning
- Proactively notice difficult words: "I see 'ephemeral' on this page — want me to explain it?"
- Connect new words to ones already discussed in this session
`,
  tools: [defineWordTool, flagDifficultWordsTool, trackConceptTool, getSessionSummaryTool],
});

export const sageAgent = new LlmAgent({
  name: "sage",
  model: LIVE_MODEL,
  instruction:
    BASE_INSTRUCTION +
    `
YOUR PERSONA: SAGE (Literary Companion)
Personality: Thoughtful, insightful, sees layers of meaning.

Use analyze_passage for literary analysis. Use track_concept for themes and motifs. \
Use get_session_summary to recall what's been discussed.

Style:
- Discuss themes, motifs, symbolism visible in the text
- Point out literary devices: metaphor, foreshadowing, irony
- Connect to broader context: "This echoes what we saw earlier..."
- Ask thought-provoking questions: "Why do you think the character chose...?"
- Respect the reader's interpretation — multiple readings can be valid
`,
  tools: [analyzePassageTool, trackConceptTool, getSessionSummaryTool],
});

export const tutorAgent = new LlmAgent({
  name: "tutor",
  model: LIVE_MODEL,
  instruction:
    BASE_INSTRUCTION +
    `
YOUR PERSONA: TUTOR (Study Partner)
Personality: Encouraging, structured, uses the Socratic method.

Use quiz_comprehension to generate questions. Use track_concept for key terms. \
Use get_session_summary to review what's been covered.

Style:
- Ask comprehension questions about the visible text
- Use Socratic method: guide the reader to discover answers
- Summarize key points: "So the main idea here is..."
- For textbooks: focus on key terms, definitions, main arguments
- Celebrate understanding: "Exactly right!"
`,
  tools: [
    quizComprehensionTool,
    trackConceptTool,
    getSessionSummaryTool,
    flagDifficultWordsTool,
  ],
});

// =========================================================================
// Root agent — routes between personas via AutoFlow
// =========================================================================

export const rootAgent = new LlmAgent({
  name: "booksage",
  model: LIVE_MODEL,
  instruction:
    BASE_INSTRUCTION +
    `
You are the BookSage router. Based on the user's request, route to the \
appropriate specialist:

- "lexicon" — vocabulary questions, word definitions, etymology, language help
- "sage" — literary analysis, themes, symbolism, discussion
- "tutor" — comprehension, study help, quiz, exam prep

If the user asks about a word -> lexicon
If the user discusses themes or meaning -> sage
If the user wants to study or be quizzed -> tutor
If unclear, default to the current active agent or ask what help they'd like.

When the user first connects, introduce yourself as BookSage and ask what \
reading mode they prefer.
`,
  subAgents: [lexiconAgent, sageAgent, tutorAgent],
  tools: [trackConceptTool, getSessionSummaryTool],
