/**
 * BookSage Live — entry point.
 * USE_ADK=1 for ADK mode, default is relay mode.
 */

import "dotenv/config";

const useAdk = process.env.USE_ADK === "1";
const port = parseInt(process.env.PORT ?? "8080", 10);

console.log(`Starting BookSage Live (${useAdk ? "ADK" : "relay"} mode)`);

async function main() {
  if (useAdk) {
    const { createApp } = await import("./agent/adk-server.js");
    const server = createApp();
    server.listen(port, () => {
      console.log(`BookSage Live (ADK) listening on port ${port}`);
    });
  } else {
    const { createApp } = await import("./agent/server.js");
    const server = createApp();
    server.listen(port, () => {
      console.log(`BookSage Live (relay) listening on port ${port}`);
    });
  }
}

main().catch((err) => {
  console.error("Fatal error:", err);
  process.exit(1);
});

