              ws.send(response.data, { binary: true });
            } else {
              pendingAudioChunks.push(
                Buffer.isBuffer(response.data)
                  ? response.data
                  : Buffer.from(response.data)
              );
            }
          }

          // User speech transcription
          if (
            response.serverContent &&
            (response.serverContent as any).inputTranscription
          ) {
            const userText = (response.serverContent as any).inputTranscription;
            const text = (userText?.text ?? "").trim();
            if (text) {
              bufInput = text;
              turnHasUserSpeech = true;
              // Flush pending audio now that we know user spoke
              while (pendingAudioChunks.length > 0) {
                ws.send(pendingAudioChunks.shift()!, { binary: true });
              }
            }
          }

          // Agent output transcription
          if (response.text) {
            const text = response.text.trim();
            if (text) {
              bufOutput = text;
            }
          }

          // Tool calls from Gemini
          if (response.toolCall) {
            for (const fc of response.toolCall.functionCalls ?? []) {
              const args = (fc.args ?? {}) as Record<string, unknown>;

              // Send visual event to frontend
              const visualEvent = toolCallToVisualEvent(fc.name!, args);
              if (visualEvent) {
                ws.send(JSON.stringify(visualEvent));
              }

              // Send tool_call notification to frontend
              ws.send(
                JSON.stringify({
                  type: "tool_call",
                  name: fc.name,
                  args,
                })
              );

              // Execute tool locally
              const result = executeToolLocally(fc.name!, args);

              // Send tool_result to frontend
              ws.send(
                JSON.stringify({
                  type: "tool_result",
                  name: fc.name,
                  result,
                })
              );

              // Send function response back to Gemini
              await session.sendToolResponse({
                functionResponses: [
                  {
                    name: fc.name!,
                    response: result,
                    id: fc.id,
                  },
                ],
              });
            }
          }

          // Turn complete
          if (
            response.serverContent &&
            (response.serverContent as any).turnComplete
          ) {
            if (turnHasUserSpeech && bufInput) {
              ws.send(
                JSON.stringify({ type: "input_transcript", text: bufInput })
              );
              bufInput = "";
            }
            if (turnHasUserSpeech && bufOutput) {
              ws.send(
                JSON.stringify({ type: "output_transcript", text: bufOutput })
              );
              bufOutput = "";
            }
            pendingAudioChunks.length = 0;
            if (turnHasUserSpeech) {
              ws.send(JSON.stringify({ type: "turn_complete" }));
            }
            turnHasUserSpeech = false;
          }

          // Interrupted
          if ((response as any).serverContent?.interrupted) {
            if (turnHasUserSpeech && bufInput) {
              ws.send(
                JSON.stringify({ type: "input_transcript", text: bufInput })
              );
              bufInput = "";
            }
            if (turnHasUserSpeech && bufOutput) {
              ws.send(
                JSON.stringify({ type: "output_transcript", text: bufOutput })
              );
              bufOutput = "";
            }
            pendingAudioChunks.length = 0;
            if (turnHasUserSpeech) {
              ws.send(JSON.stringify({ type: "interrupted" }));
            }
            turnHasUserSpeech = false;
          }
        }
      } catch (e: any) {
        if (!closed && !String(e).toLowerCase().includes("close")) {
          console.log(`[${APP_NAME}] send error:`, e?.message);
        }
      }
    };

    await Promise.all([receiveFromClient(), sendToClient()]);
    closed = true;
  } catch (e: any) {
    console.error(`[${APP_NAME}] WebSocket error:`, e);
    try {
      ws.send(JSON.stringify({ type: "error", message: String(e) }));
    } catch {}
  } finally {
    console.log(`[${APP_NAME}] Client disconnected: ${sessionId}`);
    try {
      ws.close();
    } catch {}
  }
}

