async function startSession() {
  document.getElementById('btnStart').disabled = true;
  document.getElementById('btnStop').disabled = false;
  setStatus('connecting');

  try {
    mediaStream = await navigator.mediaDevices.getUserMedia({
      // With MIDI as the source of musical truth, the mic is now for speech only.
      // Optimize for conversation so Gemini does not hear its own playback or room bleed.
      audio: {
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true,
        channelCount: 1
      },
      video: { width: 640, height: 480, facingMode: 'user' }
    });

    var video = document.getElementById('cameraVideo');
    video.srcObject = mediaStream;
    cameraEnabled = true;
    handLandmarks = [];
    detectedHandCount = 0;
    bothHandsDetected = false;
    handTrackingError = false;
    lastSentHandState = '';
    lastSentCameraState = '';
    updateCameraUi();
    initHandTracking();

    audioCtx = new AudioContext({ sampleRate: 16000 });
    var source = audioCtx.createMediaStreamSource(mediaStream);
    analyser = audioCtx.createAnalyser();
    analyser.fftSize = 2048;
    analyser.smoothingTimeConstant = 0.8;
    source.connect(analyser);
    processor = audioCtx.createScriptProcessor(4096, 1, 1);
    source.connect(processor);
    processor.connect(audioCtx.destination);

    playbackCtx = new AudioContext({ sampleRate: 24000 });
    nextPlayTime = 0;
    processor.onaudioprocess = function(e) {
      if (!ws || ws.readyState !== WebSocket.OPEN) return;
      if (playbackCtx && playbackCtx.currentTime < playbackActiveUntil) return;
      var input = e.inputBuffer.getChannelData(0);
      var pcm16 = new Int16Array(input.length);
