  1→/**
  2→ * PianoQuest Live — Express + WebSocket server with @google/genai Live API.
  3→ *
  4→ * ADK TS v0.5 does not have runLive() — we use the @google/genai Live API
  5→ * directly with manual tool execution. The genai Live API is callback-based:
  6→ * we pass an `onmessage` callback to `client.live.connect()`.
  7→ */
  8→
  9→import express from "express";
 10→import { createServer } from "http";
 11→import path from "path";
 12→import { WebSocketServer, WebSocket } from "ws";
 13→import { GoogleGenAI } from "@google/genai";
 14→import type { IncomingMessage } from "http";
 15→import {
 16→  LIVE_MODEL,
 17→  STORYTELLER_INSTRUCTION,
 18→  buildToolDeclarations,
 19→  executeToolLocally,
 20→  toolCallToVisualEvent,
 21→} from "./agent.js";
 22→
 23→const APP_NAME = "pianoquest";
 24→const STATIC_DIR = path.join(__dirname, "..", "..", "static");
 25→
 26→const NOTE_NAMES = ["C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"];
 27→
 28→function midiNoteName(note: number): string {
 29→  const octave = Math.floor(note / 12) - 1;
 30→  return `${NOTE_NAMES[note % 12]}${octave}`;
 31→}
 32→
 33→function describeMidiSnapshot(
 34→  msg: Record<string, unknown>,
 35→  cameraEnabled: boolean,
 36→  bothHandsDetected: boolean,
 37→  detectedHandCount: number
 38→): string | null {
 39→  const recentNotes = (msg.recent_notes as Array<Record<string, unknown>>) ?? [];
 40→  const activeNotes = (msg.active_notes as Array<Record<string, unknown>>) ?? [];
 41→  const detectedTechniques = (msg.detected_techniques as unknown[]) ?? [];
 42→  const pedalDown = Boolean(msg.pedal_down);
 43→  const bpm = msg.bpm as number | undefined;
 44→  const score = msg.score as number | undefined;
 45→
 46→  const noteBits: string[] = [];
 47→  for (const item of recentNotes.slice(0, 8)) {
 48→    const note = item.note as number | undefined;
 49→    const velocity = item.velocity as number | undefined;
 50→    if (typeof note === "number") {
 51→      noteBits.push(
 52→        typeof velocity === "number"
 53→          ? `${midiNoteName(note)}@${velocity}`
 54→          : midiNoteName(note)
 55→      );
 56→    }
 57→  }
 58→
 59→  const activeBits: string[] = [];
 60→  for (const item of activeNotes.slice(0, 8)) {
 61→    const note = item.note as number | undefined;
 62→    const velocity = item.velocity as number | undefined;
 63→    if (typeof note === "number") {
 64→      activeBits.push(
 65→        typeof velocity === "number"
 66→          ? `${midiNoteName(note)}@${velocity}`
 67→          : midiNoteName(note)
 68→      );
 69→    }
 70→  }
 71→
 72→  const hasPerformanceSignal = recentNotes.length > 0 || activeNotes.length > 0 || pedalDown;
 73→  if (!hasPerformanceSignal) return null;
 74→
 75→  const details: string[] = [];
 76→  if (noteBits.length > 0) details.push("recent notes: " + noteBits.join(", "));
 77→  if (activeBits.length > 0) details.push("currently held: " + activeBits.join(", "));
 78→  details.push(pedalDown ? "sustain pedal is down" : "sustain pedal is up");
 79→  if (bpm) details.push(`target tempo ${bpm} BPM`);
 80→  if (score !== undefined) details.push(`current technique score ${score}`);
 81→  if (detectedTechniques.length > 0) {
 82→    details.push(
 83→      "detected techniques: " + detectedTechniques.slice(0, 6).map(String).join(", ")
 84→    );
 85→  }
 86→
 87→  if (details.length === 0) return null;
 88→
 89→  const visionState = !cameraEnabled
 90→    ? "Camera is off; do not claim visual observations."
 91→    : bothHandsDetected
 92→      ? "Both hands are visible; finger-specific visual coaching is allowed if it matches the MIDI evidence."
 93→      : `Both hands are not fully visible (detected hands: ${detectedHandCount}); do not claim finger-specific visual observations.`;
 94→
 95→  return (
 96→    "MIDI performance update from the digital piano. " +
 97→    details.join(". ") +
 98→    ". " +
 99→    visionState +
100→    " Use this instead of piano microphone audio for note, timing, and dynamics analysis."
101→  );
102→}
103→
104→// =========================================================================
105→// Express + WebSocket server
106→// =========================================================================
107→
108→export function createApp() {
109→  const app = express();
110→  const server = createServer(app);
111→  const wss = new WebSocketServer({ noServer: true });
112→
113→  app.get("/health", (_req, res) => {
114→    res.json({ status: "ok", service: APP_NAME, modes: ["storyteller"] });
115→  });
116→
117→  app.get("/", (_req, res) => {
118→    res.sendFile(path.join(STATIC_DIR, "index.html"));
119→  });
120→
121→  app.use("/static", express.static(STATIC_DIR));
122→
123→  server.on("upgrade", (request: IncomingMessage, socket, head) => {
124→    const url = new URL(request.url ?? "/", `http://${request.headers.host}`);
125→    if (url.pathname === "/ws/dialog") {
126→      wss.handleUpgrade(request, socket, head, (ws) => {
127→        wss.emit("connection", ws, request);
128→      });
129→    } else {
130→      socket.destroy();
131→    }
132→  });
133→
134→  wss.on("connection", (ws: WebSocket) => {
135→    handleWebSocket(ws);
136→  });
137→
138→  return server;
139→}
140→
141→// =========================================================================
142→// WebSocket handler — Gemini Live session (callback-based API)
143→// =========================================================================
144→
145→function randomHex(bytes: number): string {
146→  const arr = new Uint8Array(bytes);
147→  require("crypto").randomFillSync(arr);
148→  return Buffer.from(arr).toString("hex");
149→}
150→
151→async function* wsMessages(
152→  ws: WebSocket
153→): AsyncGenerator<Buffer | string, void, undefined> {
154→  const queue: (Buffer | string)[] = [];
155→  let resolve: (() => void) | null = null;
156→  let done = false;
157→
158→  ws.on("message", (data: Buffer | string) => {
159→    queue.push(data);
160→    if (resolve) {
161→      resolve();
162→      resolve = null;
163→    }
164→  });
165→
166→  ws.on("close", () => {
167→    done = true;
168→    if (resolve) {
169→      resolve();
170→      resolve = null;
171→    }
172→  });
173→
174→  ws.on("error", () => {
175→    done = true;
176→    if (resolve) {
177→      resolve();
178→      resolve = null;
179→    }
180→  });
181→
182→  while (true) {
183→    if (queue.length > 0) {
184→      yield queue.shift()!;
185→    } else if (done) {
186→      return;
187→    } else {
188→      await new Promise<void>((r) => {
189→        resolve = r;
190→      });
191→    }
192→  }
193→}
194→
195→async function handleWebSocket(ws: WebSocket) {
196→  const apiKey = process.env.GOOGLE_API_KEY ?? process.env.GEMINI_API_KEY;
197→  if (!apiKey) {
198→    ws.send(JSON.stringify({ type: "error", message: "No API key configured" }));
199→    ws.close();
200→    return;
201→  }
202→
203→  process.env.GOOGLE_API_KEY = apiKey;
204→
205→  const client = new GoogleGenAI({ apiKey });
206→  const sessionId = randomHex(4);
207→  let closed = false;
208→
209→  // Per-session state
210→  let cameraEnabled = true;
211→  let bothHandsDetected = false;
212→  let detectedHandCount = 0;
213→
214→  // Transcription buffers (gated on user speech)
215→  let bufInput = "";
216→  let bufOutput = "";
217→  let turnHasUserSpeech = false;
218→  const pendingAudioChunks: Buffer[] = [];
219→
220→  console.log(`[${APP_NAME}] Client connected: ${sessionId}`);
221→
222→  const liveConfig: Record<string, unknown> = {
223→    response_modalities: ["AUDIO"],
224→    system_instruction: STORYTELLER_INSTRUCTION,
225→    speech_config: {
226→      voice_config: {
227→        prebuilt_voice_config: { voice_name: "Puck" },
228→      },
229→    },
230→    input_audio_transcription: {},
231→    output_audio_transcription: {},
232→    realtime_input_config: {
233→      automatic_activity_detection: {
234→        disabled: false,
235→        silence_duration_ms: 1000,
236→      },
237→    },
238→    tools: buildToolDeclarations(),
239→  };
240→
241→  try {
242→    const session = await client.live.connect({
243→      model: LIVE_MODEL,
244→      config: liveConfig as any,
245→      callbacks: {
246→        onopen: () => {
247→          console.log(`[${APP_NAME}] Gemini Live session opened: ${sessionId}`);
248→        },
249→        onmessage: (msg: any) => {
250→          if (closed) return;
251→
252→          try {
253→            // Audio data from model turn
254→            if (msg.serverContent?.modelTurn?.parts) {
255→              for (const part of msg.serverContent.modelTurn.parts) {
256→                if (part.inlineData?.data) {
257→                  const audioBuffer = Buffer.from(part.inlineData.data, "base64");
258→                  if (turnHasUserSpeech) {
259→                    ws.send(audioBuffer, { binary: true });
260→                  } else {
261→                    pendingAudioChunks.push(audioBuffer);
262→                  }
263→                }
264→                if (part.text) {
265→                  const text = part.text.trim();
266→                  if (text) {
267→                    bufOutput = text;
268→                  }
269→                }
270→              }
271→            }
272→
273→            // Input transcription (user speech)
274→            if (msg.serverContent?.inputTranscription?.text) {
275→              const text = msg.serverContent.inputTranscription.text.trim();
276→              if (text) {
277→                bufInput = text;
278→                turnHasUserSpeech = true;
279→                // Flush pending audio now that we know user spoke
280→                while (pendingAudioChunks.length > 0) {
281→                  ws.send(pendingAudioChunks.shift()!, { binary: true });
282→                }
283→              }
284→            }
285→
286→            // Output transcription
287→            if (msg.serverContent?.outputTranscription?.text) {
288→              const text = msg.serverContent.outputTranscription.text.trim();
289→              if (text) {
290→                bufOutput = text;
291→              }
292→            }
293→
294→            // Tool calls from Gemini
295→            if (msg.toolCall?.functionCalls) {
296→              for (const fc of msg.toolCall.functionCalls) {
297→                const args = (fc.args ?? {}) as Record<string, unknown>;
298→
299→                // Send visual event to frontend
300→                const visualEvent = toolCallToVisualEvent(fc.name!, args);
301→                if (visualEvent) {
302→                  ws.send(JSON.stringify(visualEvent));
303→                }
304→
305→                // Send tool_call notification to frontend
306→                ws.send(
307→                  JSON.stringify({
308→                    type: "tool_call",
309→                    name: fc.name,
310→                    args,
311→                  })
312→                );
313→
314→                // Execute tool locally
315→                const result = executeToolLocally(fc.name!, args);
316→
317→                // Send tool_result to frontend
318→                ws.send(
319→                  JSON.stringify({
320→                    type: "tool_result",
321→                    name: fc.name,
322→                    result,
323→                  })
324→                );
325→
326→                // Send function response back to Gemini
327→                session.sendToolResponse({
328→                  functionResponses: [
329→                    {
330→                      name: fc.name!,
331→                      response: result,
332→                      id: fc.id,
333→                    },
334→                  ],
335→                });
336→              }
337→            }
338→
339→            // Turn complete
340→            if (msg.serverContent?.turnComplete) {
341→              if (turnHasUserSpeech && bufInput) {
342→                ws.send(
343→                  JSON.stringify({ type: "input_transcript", text: bufInput })
344→                );
345→                bufInput = "";
346→              }
347→              if (turnHasUserSpeech && bufOutput) {
348→                ws.send(
349→                  JSON.stringify({ type: "output_transcript", text: bufOutput })
350→                );
351→                bufOutput = "";
352→              }
353→              pendingAudioChunks.length = 0;
354→              if (turnHasUserSpeech) {
355→                ws.send(JSON.stringify({ type: "turn_complete" }));
356→              }
357→              turnHasUserSpeech = false;
358→            }
359→
360→            // Interrupted
361→            if (msg.serverContent?.interrupted) {
362→              if (turnHasUserSpeech && bufInput) {
363→                ws.send(
364→                  JSON.stringify({ type: "input_transcript", text: bufInput })
365→                );
366→                bufInput = "";
367→              }
368→              if (turnHasUserSpeech && bufOutput) {
369→                ws.send(
370→                  JSON.stringify({ type: "output_transcript", text: bufOutput })
371→                );
372→                bufOutput = "";
373→              }
374→              pendingAudioChunks.length = 0;
375→              if (turnHasUserSpeech) {
376→                ws.send(JSON.stringify({ type: "interrupted" }));
377→              }
378→              turnHasUserSpeech = false;
379→            }
380→          } catch (e: any) {
381→            if (!closed) {
382→              console.log(`[${APP_NAME}] onmessage error:`, e?.message);
383→            }
384→          }
385→        },
386→        onerror: (e: any) => {
387→          if (!closed) {
388→            console.log(`[${APP_NAME}] Gemini Live error:`, e?.message ?? e);
389→          }
390→        },
391→        onclose: () => {
392→          console.log(`[${APP_NAME}] Gemini Live session closed: ${sessionId}`);
393→          closed = true;
394→          try { ws.close(); } catch {}
395→        },
396→      },
397→    });
398→
399→    // ---------------------------------------------------------------
400→    // Receive from browser client, forward to Gemini
401→    // ---------------------------------------------------------------
402→    try {
403→      for await (const rawMsg of wsMessages(ws)) {
404→        if (closed) break;
405→
406→        // Binary = PCM audio at 16kHz
407→        if (rawMsg instanceof Buffer || rawMsg instanceof ArrayBuffer) {
408→          const data =
409→            rawMsg instanceof ArrayBuffer
410→              ? new Uint8Array(rawMsg)
411→              : rawMsg;
412→          session.sendRealtimeInput({
413→            audio: {
414→              data: Buffer.from(data).toString("base64"),
415→              mimeType: "audio/pcm;rate=16000",
416→            },
417→          });
418→        } else if (typeof rawMsg === "string") {
419→          const msg = JSON.parse(rawMsg);
420→          const msgType = msg.type;
421→
422→          if (msgType === "video_frame") {
423→            const frameBytes = Buffer.from(msg.data, "base64");
424→            session.sendRealtimeInput({
425→              media: {
426→                data: frameBytes.toString("base64"),
427→                mimeType: "image/jpeg",
428→              },
429→            });
