// Remote Camera Mode — ?camera=1&room=CODE
// ============================================================================
(function() {
  var params = new URLSearchParams(window.location.search);
  if (params.get('camera') !== '1') return;
  var room = params.get('room') || '';
  if (!room) {
    document.body.innerHTML = '<h1 style="color:#fff;text-align:center;margin-top:40vh">Missing room code. Use ?camera=1&room=CODE</h1>';
    return;
  }

  // Replace entire page with minimal camera UI
  document.body.innerHTML = '<div style="display:flex;flex-direction:column;align-items:center;justify-content:center;height:100vh;background:#0c0c14;color:#e2e8f0;font-family:sans-serif">' +
    '<h2 style="margin-bottom:8px">PianoQuest Camera</h2>' +
    '<div id="camStatus" style="margin-bottom:16px;color:rgba(255,255,255,0.5)">Connecting to room ' + room + '...</div>' +
    '<video id="camVideo" autoplay playsinline muted style="width:90vw;max-width:640px;border-radius:12px;background:#000"></video>' +
    '</div>';

  var proto = location.protocol === 'https:' ? 'wss' : 'ws';
  var wsUrl = proto + '://' + location.host + '/ws/camera?room=' + encodeURIComponent(room);
  var camWs = new WebSocket(wsUrl);
  var statusEl = document.getElementById('camStatus');

  camWs.onopen = function() {
    if (statusEl) statusEl.textContent = 'Connected to room ' + room;
    if (statusEl) statusEl.style.color = '#86efac';
    startCamera();
  };

  camWs.onmessage = function(event) {
    try {
      var msg = JSON.parse(event.data);
      if (msg.type === 'error' && statusEl) {
        statusEl.textContent = msg.message;
        statusEl.style.color = '#fb7185';
      }
    } catch {}
  };

  camWs.onclose = function() {
    if (statusEl) statusEl.textContent = 'Disconnected';
    if (statusEl) statusEl.style.color = '#fb7185';
  };

  function startCamera() {
    navigator.mediaDevices.getUserMedia({
      video: { width: 640, height: 480, facingMode: 'environment' }
    }).then(function(stream) {
      var video = document.getElementById('camVideo');
      if (video) video.srcObject = stream;

      var canvas = document.createElement('canvas');
      canvas.width = 640;
      canvas.height = 480;
      var ctx = canvas.getContext('2d');

      setInterval(function() {
        if (camWs.readyState !== WebSocket.OPEN) return;
        if (!video || video.readyState < 2) return;
        ctx.drawImage(video, 0, 0, 640, 480);
        var dataUrl = canvas.toDataURL('image/jpeg', 0.6);
        var base64 = dataUrl.split(',')[1];
        camWs.send(JSON.stringify({ type: 'video_frame', data: base64 }));
      }, 1000);
    }).catch(function(err) {
      if (statusEl) statusEl.textContent = 'Camera error: ' + err.message;
      if (statusEl) statusEl.style.color = '#fb7185';
    });
  }
})();
</script>

