// Remote Camera Mode — ?camera=1&room=CODE
// ============================================================================
(function() {
  var params = new URLSearchParams(window.location.search);
  if (params.get('camera') !== '1') return;
  var room = params.get('room') || '';
  if (!room) return;

  // Replace page with minimal camera UI using safe DOM methods
  while (document.body.firstChild) document.body.removeChild(document.body.firstChild);
  document.body.style.cssText = 'display:flex;flex-direction:column;align-items:center;justify-content:center;height:100vh;background:#0c0c14;color:#e2e8f0;font-family:sans-serif';

  var heading = document.createElement('h2');
  heading.textContent = 'PianoQuest Camera';
  heading.style.marginBottom = '8px';
  document.body.appendChild(heading);

  var statusEl = document.createElement('div');
  statusEl.style.cssText = 'margin-bottom:16px;color:rgba(255,255,255,0.5)';
  statusEl.textContent = 'Connecting to room ' + room + '...';
  document.body.appendChild(statusEl);

  var video = document.createElement('video');
  video.autoplay = true;
  video.playsInline = true;
  video.muted = true;
  video.style.cssText = 'width:90vw;max-width:640px;border-radius:12px;background:#000';
  document.body.appendChild(video);

  var proto = location.protocol === 'https:' ? 'wss' : 'ws';
  var wsUrl = proto + '://' + location.host + '/ws/camera?room=' + encodeURIComponent(room);
  var camWs = new WebSocket(wsUrl);

  camWs.onopen = function() {
    statusEl.textContent = 'Connected to room ' + room;
