  1→/**
  2→ * PianoQuest Live — Express + WebSocket server with @google/genai Live API.
  3→ *
  4→ * ADK TS v0.5 does not have runLive() — we use the @google/genai Live API
  5→ * directly with manual tool execution. The genai Live API is callback-based:
  6→ * we pass an `onmessage` callback to `client.live.connect()`.
  7→ */
  8→
  9→import express from "express";
 10→import { createServer } from "http";
 11→import path from "path";
 12→import { WebSocketServer, WebSocket } from "ws";
 13→import { GoogleGenAI } from "@google/genai";
 14→import type { IncomingMessage } from "http";
 15→import {
 16→  LIVE_MODEL,
 17→  STORYTELLER_INSTRUCTION,
 18→  buildToolDeclarations,
 19→  executeToolLocally,
 20→  toolCallToVisualEvent,
 21→} from "./agent.js";
 22→
 23→const APP_NAME = "pianoquest";
 24→const STATIC_DIR = path.join(__dirname, "..", "..", "static");
 25→
 26→const NOTE_NAMES = ["C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"];
 27→
 28→function midiNoteName(note: number): string {
 29→  const octave = Math.floor(note / 12) - 1;
 30→  return `${NOTE_NAMES[note % 12]}${octave}`;
 31→}
 32→
 33→function describeMidiSnapshot(
 34→  msg: Record<string, unknown>,
 35→  cameraEnabled: boolean,
 36→  bothHandsDetected: boolean,
 37→  detectedHandCount: number
 38→): string | null {
 39→  const recentNotes = (msg.recent_notes as Array<Record<string, unknown>>) ?? [];
 40→  const activeNotes = (msg.active_notes as Array<Record<string, unknown>>) ?? [];
 41→  const detectedTechniques = (msg.detected_techniques as unknown[]) ?? [];
 42→  const pedalDown = Boolean(msg.pedal_down);
 43→  const bpm = msg.bpm as number | undefined;
 44→  const score = msg.score as number | undefined;
 45→
 46→  const noteBits: string[] = [];
 47→  for (const item of recentNotes.slice(0, 8)) {
 48→    const note = item.note as number | undefined;
 49→    const velocity = item.velocity as number | undefined;
 50→    if (typeof note === "number") {
 51→      noteBits.push(
 52→        typeof velocity === "number"
 53→          ? `${midiNoteName(note)}@${velocity}`
 54→          : midiNoteName(note)
 55→      );
 56→    }
 57→  }
 58→
 59→  const activeBits: string[] = [];
 60→  for (const item of activeNotes.slice(0, 8)) {
 61→    const note = item.note as number | undefined;
 62→    const velocity = item.velocity as number | undefined;
 63→    if (typeof note === "number") {
 64→      activeBits.push(
 65→        typeof velocity === "number"
 66→          ? `${midiNoteName(note)}@${velocity}`
 67→          : midiNoteName(note)
 68→      );
 69→    }
 70→  }
 71→
 72→  const hasPerformanceSignal = recentNotes.length > 0 || activeNotes.length > 0 || pedalDown;
 73→  if (!hasPerformanceSignal) return null;
 74→
 75→  const details: string[] = [];
 76→  if (noteBits.length > 0) details.push("recent notes: " + noteBits.join(", "));
 77→  if (activeBits.length > 0) details.push("currently held: " + activeBits.join(", "));
 78→  details.push(pedalDown ? "sustain pedal is down" : "sustain pedal is up");
 79→  if (bpm) details.push(`target tempo ${bpm} BPM`);
 80→  if (score !== undefined) details.push(`current technique score ${score}`);
 81→  if (detectedTechniques.length > 0) {
 82→    details.push(
 83→      "detected techniques: " + detectedTechniques.slice(0, 6).map(String).join(", ")
 84→    );
 85→  }
 86→
 87→  if (details.length === 0) return null;
 88→
 89→  const visionState = !cameraEnabled
 90→    ? "Camera is off; do not claim visual observations."
 91→    : bothHandsDetected
 92→      ? "Both hands are visible; finger-specific visual coaching is allowed if it matches the MIDI evidence."
 93→      : `Both hands are not fully visible (detected hands: ${detectedHandCount}); do not claim finger-specific visual observations.`;
 94→
 95→  return (
 96→    "MIDI performance update from the digital piano. " +
 97→    details.join(". ") +
 98→    ". " +
 99→    visionState +
100→    " Use this instead of piano microphone audio for note, timing, and dynamics analysis."
101→  );
102→}
103→
104→// =========================================================================
105→// Spectator broadcasting — spectators receive all output but send nothing
106→// =========================================================================
107→
108→const spectators = new Set<WebSocket>();
109→
110→function broadcast(data: Buffer | string, binary = false) {
111→  for (const s of spectators) {
112→    if (s.readyState === WebSocket.OPEN) {
113→      try { s.send(data, { binary }); } catch {}
114→    }
115→  }
116→}
117→
118→// =========================================================================
119→// Room-based session sharing — remote camera sends frames to primary session
120→// =========================================================================
121→
122→interface RoomSession {
123→  sendRealtimeInput: (input: any) => void;
124→}
125→
126→const rooms = new Map<string, RoomSession>();
127→
128→function generateRoomCode(): string {
129→  const chars = "REDACTED";
130→  let code = "";
131→  const arr = new Uint8Array(4);
132→  require("crypto").randomFillSync(arr);
133→  for (let i = 0; i < 4; i++) {
134→    code += chars[arr[i] % chars.length];
135→  }
136→  return code;
137→}
138→
139→// =========================================================================
140→// Express + WebSocket server
141→// =========================================================================
142→
143→export function createApp() {
144→  const app = express();
145→  const server = createServer(app);
146→  const wssDialog = new WebSocketServer({ noServer: true });
147→  const wssSpectator = new WebSocketServer({ noServer: true });
148→  const wssCamera = new WebSocketServer({ noServer: true });
149→
150→  app.get("/health", (_req, res) => {
151→    res.json({
152→      status: "ok",
153→      service: APP_NAME,
154→      modes: ["storyteller"],
155→      spectators: spectators.size,
156→      rooms: rooms.size,
157→    });
158→  });
159→
160→  app.get("/", (_req, res) => {
161→    res.sendFile(path.join(STATIC_DIR, "index.html"));
162→  });
163→
164→  app.use("/static", express.static(STATIC_DIR));
165→
166→  server.on("upgrade", (request: IncomingMessage, socket, head) => {
167→    const url = new URL(request.url ?? "/", `http://${request.headers.host}`);
168→    if (url.pathname === "/ws/dialog") {
169→      wssDialog.handleUpgrade(request, socket, head, (ws) => {
170→        wssDialog.emit("connection", ws, request);
171→      });
172→    } else if (url.pathname === "/ws/spectator") {
173→      wssSpectator.handleUpgrade(request, socket, head, (ws) => {
174→        wssSpectator.emit("connection", ws, request);
175→      });
176→    } else if (url.pathname === "/ws/camera") {
177→      const room = url.searchParams.get("room") ?? "";
178→      wssCamera.handleUpgrade(request, socket, head, (ws) => {
179→        (ws as any)._room = room;
180→        wssCamera.emit("connection", ws, request);
181→      });
182→    } else {
183→      socket.destroy();
184→    }
185→  });
186→
187→  wssDialog.on("connection", (ws: WebSocket) => {
188→    handleWebSocket(ws);
189→  });
190→
191→  wssSpectator.on("connection", (ws: WebSocket) => {
192→    console.log(`[${APP_NAME}] Spectator connected (total: ${spectators.size + 1})`);
193→    spectators.add(ws);
194→    ws.on("close", () => {
195→      spectators.delete(ws);
196→      console.log(`[${APP_NAME}] Spectator disconnected (total: ${spectators.size})`);
197→    });
198→    ws.on("error", () => {
199→      spectators.delete(ws);
200→    });
201→  });
202→
203→  wssCamera.on("connection", (ws: WebSocket) => {
204→    const room = (ws as any)._room as string;
205→    const session = rooms.get(room);
206→    if (!session) {
207→      console.log(`[${APP_NAME}] Camera rejected — room "${room}" not found`);
208→      ws.send(JSON.stringify({ type: "error", message: `Room "${room}" not found` }));
209→      ws.close();
210→      return;
211→    }
212→
213→    console.log(`[${APP_NAME}] Remote camera connected to room "${room}"`);
214→    ws.send(JSON.stringify({ type: "camera_connected", room }));
215→
216→    ws.on("message", (data: Buffer | string) => {
217→      if (typeof data === "string") {
218→        try {
219→          const msg = JSON.parse(data);
220→          if (msg.type === "video_frame" && msg.data) {
221→            const frameBytes = Buffer.from(msg.data, "base64");
222→            session.sendRealtimeInput({
223→              media: {
224→                data: frameBytes.toString("base64"),
225→                mimeType: "image/jpeg",
226→              },
227→            });
228→          }
229→        } catch {}
230→      }
231→    });
232→
233→    ws.on("close", () => {
234→      console.log(`[${APP_NAME}] Remote camera disconnected from room "${room}"`);
235→    });
236→  });
237→
238→  return server;
239→}
240→
241→// =========================================================================
242→// WebSocket handler — Gemini Live session (callback-based API)
243→// =========================================================================
244→
245→function randomHex(bytes: number): string {
246→  const arr = new Uint8Array(bytes);
247→  require("crypto").randomFillSync(arr);
248→  return Buffer.from(arr).toString("hex");
249→}
250→
251→async function* wsMessages(
252→  ws: WebSocket
253→): AsyncGenerator<Buffer | string, void, undefined> {
254→  const queue: (Buffer | string)[] = [];
255→  let resolve: (() => void) | null = null;
256→  let done = false;
257→
258→  ws.on("message", (data: Buffer | string) => {
259→    queue.push(data);
260→    if (resolve) {
261→      resolve();
262→      resolve = null;
263→    }
264→  });
265→
266→  ws.on("close", () => {
267→    done = true;
268→    if (resolve) {
269→      resolve();
270→      resolve = null;
271→    }
272→  });
273→
274→  ws.on("error", () => {
275→    done = true;
276→    if (resolve) {
277→      resolve();
278→      resolve = null;
279→    }
280→  });
281→
282→  while (true) {
283→    if (queue.length > 0) {
284→      yield queue.shift()!;
285→    } else if (done) {
286→      return;
287→    } else {
288→      await new Promise<void>((r) => {
289→        resolve = r;
290→      });
291→    }
292→  }
293→}
294→
295→async function handleWebSocket(ws: WebSocket) {
296→  const apiKey = process.env.GOOGLE_API_KEY ?? process.env.GEMINI_API_KEY;
297→  if (!apiKey) {
298→    ws.send(JSON.stringify({ type: "error", message: "No API key configured" }));
299→    ws.close();
300→    return;
301→  }
302→
303→  process.env.GOOGLE_API_KEY = apiKey;
304→
305→  const client = new GoogleGenAI({ apiKey });
306→  const sessionId = randomHex(4);
307→  const roomCode = generateRoomCode();
308→  let closed = false;
309→
310→  // Per-session state
311→  let cameraEnabled = true;
312→  let bothHandsDetected = false;
313→  let detectedHandCount = 0;
314→
315→  // Transcription buffers (gated on user speech)
316→  let bufInput = "";
317→  let bufOutput = "";
318→  let turnHasUserSpeech = false;
319→  const pendingAudioChunks: Buffer[] = [];
320→
321→  console.log(`[${APP_NAME}] Client connected: ${sessionId}, room: ${roomCode}`);
322→
323→  const liveConfig: Record<string, unknown> = {
324→    response_modalities: ["AUDIO"],
325→    system_instruction: STORYTELLER_INSTRUCTION,
326→    speech_config: {
327→      voice_config: {
328→        prebuilt_voice_config: { voice_name: "Puck" },
329→      },
330→    },
331→    input_audio_transcription: {},
332→    output_audio_transcription: {},
333→    realtime_input_config: {
334→      automatic_activity_detection: {
335→        disabled: false,
336→        silence_duration_ms: 1000,
337→      },
338→    },
339→    tools: buildToolDeclarations(),
340→  };
341→
342→  try {
343→    const session = await client.live.connect({
344→      model: LIVE_MODEL,
345→      config: liveConfig as any,
346→      callbacks: {
347→        onopen: () => {
348→          console.log(`[${APP_NAME}] Gemini Live session opened: ${sessionId}, room: ${roomCode}`);
349→          // Register room so remote cameras can join
350→          rooms.set(roomCode, session);
351→          // Send room code to primary client
352→          ws.send(JSON.stringify({ type: "room_code", room: roomCode }));
353→        },
354→        onmessage: (msg: any) => {
355→          if (closed) return;
356→
357→          try {
358→            // Helper: send to primary + all spectators
359→            const sendAll = (data: Buffer | string, binary = false) => {
360→              if (binary) {
361→                ws.send(data, { binary: true });
362→              } else {
363→                ws.send(data);
364→              }
365→              broadcast(data, binary);
366→            };
367→
368→            // Audio data from model turn
369→            if (msg.serverContent?.modelTurn?.parts) {
370→              for (const part of msg.serverContent.modelTurn.parts) {
371→                if (part.inlineData?.data) {
372→                  const audioBuffer = Buffer.from(part.inlineData.data, "base64");
373→                  if (turnHasUserSpeech) {
374→                    sendAll(audioBuffer, true);
375→                  } else {
376→                    pendingAudioChunks.push(audioBuffer);
377→                  }
378→                }
379→                if (part.text) {
380→                  const text = part.text.trim();
381→                  if (text) {
382→                    bufOutput = text;
383→                  }
384→                }
385→              }
386→            }
387→
388→            // Input transcription (user speech)
389→            if (msg.serverContent?.inputTranscription?.text) {
390→              const text = msg.serverContent.inputTranscription.text.trim();
391→              if (text) {
392→                bufInput = text;
393→                turnHasUserSpeech = true;
394→                // Flush pending audio now that we know user spoke
395→                while (pendingAudioChunks.length > 0) {
396→                  sendAll(pendingAudioChunks.shift()!, true);
397→                }
398→              }
399→            }
400→
401→            // Output transcription
402→            if (msg.serverContent?.outputTranscription?.text) {
403→              const text = msg.serverContent.outputTranscription.text.trim();
404→              if (text) {
405→                bufOutput = text;
406→              }
407→            }
408→
409→            // Tool calls from Gemini
410→            if (msg.toolCall?.functionCalls) {
411→              for (const fc of msg.toolCall.functionCalls) {
412→                const args = (fc.args ?? {}) as Record<string, unknown>;
413→
414→                // Send visual event to frontend
415→                const visualEvent = toolCallToVisualEvent(fc.name!, args);
416→                if (visualEvent) {
417→                  sendAll(JSON.stringify(visualEvent));
418→                }
419→
420→                // Send tool_call notification to frontend
421→                sendAll(
422→                  JSON.stringify({
423→                    type: "tool_call",
424→                    name: fc.name,
425→                    args,
426→                  })
427→                );
428→
429→                // Execute tool locally
430→                const result = executeToolLocally(fc.name!, args);
431→
432→                // Send tool_result to frontend
433→                sendAll(
434→                  JSON.stringify({
435→                    type: "tool_result",
436→                    name: fc.name,
437→                    result,
438→                  })
439→                );
440→
441→                // Send function response back to Gemini
442→                session.sendToolResponse({
443→                  functionResponses: [
444→                    {
445→                      name: fc.name!,
446→                      response: result,
447→                      id: fc.id,
448→                    },
449→                  ],
450→                });
451→              }
452→            }
453→
454→            // Turn complete
455→            if (msg.serverContent?.turnComplete) {
456→              if (turnHasUserSpeech && bufInput) {
457→                sendAll(
458→                  JSON.stringify({ type: "input_transcript", text: bufInput })
459→                );
460→                bufInput = "";
461→              }
462→              if (turnHasUserSpeech && bufOutput) {
463→                sendAll(
464→                  JSON.stringify({ type: "output_transcript", text: bufOutput })
465→                );
466→                bufOutput = "";
467→              }
468→              pendingAudioChunks.length = 0;
469→              if (turnHasUserSpeech) {
470→                sendAll(JSON.stringify({ type: "turn_complete" }));
471→              }
472→              turnHasUserSpeech = false;
473→            }
474→
475→            // Interrupted
476→            if (msg.serverContent?.interrupted) {
477→              if (turnHasUserSpeech && bufInput) {
478→                sendAll(
479→                  JSON.stringify({ type: "input_transcript", text: bufInput })
480→                );
481→                bufInput = "";
482→              }
483→              if (turnHasUserSpeech && bufOutput) {
484→                sendAll(
485→                  JSON.stringify({ type: "output_transcript", text: bufOutput })
486→                );
487→                bufOutput = "";
488→              }
489→              pendingAudioChunks.length = 0;
490→              if (turnHasUserSpeech) {
491→                sendAll(JSON.stringify({ type: "interrupted" }));
492→              }
493→              turnHasUserSpeech = false;
494→            }
495→          } catch (e: any) {
496→            if (!closed) {
497→              console.log(`[${APP_NAME}] onmessage error:`, e?.message);
498→            }
499→          }
500→        },
501→        onerror: (e: any) => {
502→          if (!closed) {
503→            console.log(`[${APP_NAME}] Gemini Live error:`, e?.message ?? e);
504→          }
505→        },
506→        onclose: () => {
507→          console.log(`[${APP_NAME}] Gemini Live session closed: ${sessionId}`);
508→          closed = true;
509→          try { ws.close(); } catch {}
510→        },
511→      },
512→    });
513→
514→    // ---------------------------------------------------------------
515→    // Receive from browser client, forward to Gemini
516→    // ---------------------------------------------------------------
517→    try {
518→      for await (const rawMsg of wsMessages(ws)) {
519→        if (closed) break;
520→
521→        // Binary = PCM audio at 16kHz
522→        if (rawMsg instanceof Buffer || rawMsg instanceof ArrayBuffer) {
523→          const data =
524→            rawMsg instanceof ArrayBuffer
525→              ? new Uint8Array(rawMsg)
526→              : rawMsg;
