 13→const PORT = 3491;
 14→const app = express();
 15→const httpServer = createServer(app);
 16→
 17→// Shared Supabase client for HTTP endpoints
 18→const supabase = process.env.SUPABASE_URL && process.env.SUPABASE_SERVICE_ROLE_KEY
 19→  ? createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY)
 20→  : null;
 21→
 22→// Player manager — handles queue, sessions, admin priority
 23→const playerManager = new PlayerManager(
 24→  // Broadcast player status to all viewers
 25→  (msg: PlayerStatusMessage) => {
 26→    downstream.broadcastPlayerStatus(msg);
 27→  },
 28→  // On session end — log via Edge Function
 29→  (player, durationMs) => {
 30→    console.log(`[player-manager] Session ended: ${player.displayName} (${player.userId.slice(0, 8)}) played for ${Math.round(durationMs / 1000)}s`);
 31→    if (process.env.SUPABASE_URL && process.env.SUPABASE_SERVICE_ROLE_KEY) {
 32→      fetch(process.env.SUPABASE_URL + '/functions/v1/log-play-session', {
 33→        method: 'POST',
 34→        headers: {
 35→          'Content-Type': 'application/json',
 36→          'Authorization': 'Bearer ' + process.env.SUPABASE_SERVICE_ROLE_KEY,
 37→        },
 38→        body: JSON.stringify({
 39→          user_id: player.userId,
 40→          started_at: new Date(player.connectedAt).toISOString(),
 41→          ended_at: new Date().toISOString(),
 42→          notes_played: 0, // TODO: track in player manager
 43→          source: player.source === 'desktop' ? 'desktop' : 'companion_app',
 44→        }),
 45→      }).catch(err => console.error('[bridge] Failed to log session:', err));
 46→    }
 47→  },
 48→);
 49→
 50→// Upstream client — connects to PianoQuest desktop on :3490
 51→let downstream: DownstreamServer;
 52→
 53→const upstream = new UpstreamClient(
 54→  // On upstream message: relay to all viewers
 55→  (msg) => {
 56→    downstream.relayUpstreamMessage(msg);
 57→  },
 58→  // On state change (live/offline): broadcast status + manage desktop player
 59→  (state) => {
 60→    downstream.broadcastStreamStatus();
 61→    if (state.live) {
 62→      playerManager.setDesktopPlayer();
 63→    } else {
 64→      playerManager.clearDesktopPlayer();
 65→    }
 66→  },
 67→);
 68→
 69→// Create WebSocketServer instances with noServer (manual upgrade routing)
 70→const viewerWss = new WebSocketServer({ noServer: true });
 71→const memberWss = new WebSocketServer({ noServer: true });
 72→
 73→// Downstream server — viewers connect here on /ws
 74→downstream = new DownstreamServer(
 75→  viewerWss,
 76→  () => upstream.getState(),
 77→);
 78→
 79→// Member upstream — authenticated members connect on /ws/play
 80→const memberUpstream = new MemberUpstreamServer(
 81→  memberWss,
 82→  playerManager,
 83→  // On member MIDI: relay to viewers (same as desktop upstream)
 84→  (msg) => {
 85→    downstream.relayUpstreamMessage(msg);
 86→  },
 87→);
 88→
 89→// Route WebSocket upgrades by path
 90→httpServer.on('upgrade', (request, socket, head) => {
 91→  const { pathname } = parse(request.url || '');
 92→
 93→  if (pathname === '/ws') {
 94→    viewerWss.handleUpgrade(request, socket, head, (ws) => {
 95→      viewerWss.emit('connection', ws, request);
 96→    });
 97→  } else if (pathname === '/ws/play') {
 98→    memberWss.handleUpgrade(request, socket, head, (ws) => {
 99→      memberWss.emit('connection', ws, request);
100→    });
101→  } else {
102→    socket.destroy();
103→  }
104→});
105→
106→// Parse JSON bodies
107→app.use(express.json());
108→
109→// HTTP endpoints
110→app.get('/api/status', (_req, res) => {
111→  const state: StreamState = upstream.getState();
112→  res.json({
113→    live: state.live,
114→    app: state.app,
115→    version: state.version,
116→    screen: state.screen,
117→    midiDevice: state.midiDevice,
118→    viewers: downstream.getViewerCount(),
119→    uptimeMs: state.connectedAt ? Date.now() - state.connectedAt : 0,
120→  });
121→});
122→
123→app.get('/api/health', (_req, res) => {
124→  res.json({ status: 'ok', timestamp: Date.now() });
125→});
126→
127→// Player endpoints
128→app.get('/api/play/status', (req, res) => {
129→  const userId = req.query.userId as string | undefined;
130→  res.json(playerManager.getStatus(userId));
131→});
132→
133→app.post('/api/play/request', async (req, res) => {
134→  const { token } = req.body;
135→  if (!token || typeof token !== 'string') {
136→    return res.status(400).json({ error: 'token required' });
137→  }
138→  if (!supabase) {
139→    return res.status(503).json({ error: 'Supabase not configured' });
140→  }
141→
142→  try {
143→    const { data: { user }, error } = await supabase.auth.getUser(token);
144→    if (error || !user) {
145→      return res.status(401).json({ error: 'Invalid token' });
146→    }
147→
148→    const status = playerManager.getStatus(user.id);
149→    return res.json({
150→      userId: user.id,
151→      ...status,
152→      message: 'Connect to /ws/play WebSocket to start playing',
153→    });
154→  } catch {
155→    return res.status(500).json({ error: 'Auth check failed' });
156→  }
157→});
158→
159→app.delete('/api/play/leave', async (req, res) => {
160→  const { token } = req.body;
161→  if (!token || typeof token !== 'string') {
162→    return res.status(400).json({ error: 'token required' });
163→  }
164→  if (!supabase) {
165→    return res.status(503).json({ error: 'Supabase not configured' });
166→  }
167→
168→  try {
169→    const { data: { user }, error } = await supabase.auth.getUser(token);
170→    if (error || !user) {
171→      return res.status(401).json({ error: 'Invalid token' });
172→    }
173→
174→    playerManager.removePlayer(user.id);
175→    return res.json({ left: true });
176→  } catch {
177→    return res.status(500).json({ error: 'Auth check failed' });
178→  }
179→});
180→
181→// Global chat rate limiter: 30 messages/sec across all users
182→const GLOBAL_RATE_LIMIT = 30;
183→const GLOBAL_RATE_WINDOW_MS = 1000;
184→let chatTimestamps: number[] = [];
185→
186→function isGlobalRateLimited(): boolean {
187→  const now = Date.now();
188→  chatTimestamps = chatTimestamps.filter((t) => now - t < GLOBAL_RATE_WINDOW_MS);
189→  if (chatTimestamps.length >= GLOBAL_RATE_LIMIT) return true;
190→  chatTimestamps.push(now);
191→  return false;
192→}
193→
194→const BRIDGE_SECRET = process.env.BRIDGE_SECRET || '';
195→
196→// Chat endpoint
197→app.post('/api/chat', (req, res) => {
198→  // Validate bridge secret if configured
199→  if (BRIDGE_SECRET) {
200→    const provided = req.headers['x-bridge-secret'];
201→    if (provided !== BRIDGE_SECRET) {
202→      return res.status(403).json({ error: 'Forbidden' });
203→    }
204→  }
205→
206→  // Global rate limit
207→  if (isGlobalRateLimited()) {
208→    return res.status(429).json({ error: 'Rate limited' });
209→  }
210→
211→  const { userId, viewerId, displayName, text, role, avatarUrl } = req.body;
212→
213→  // Accept userId or fall back to viewerId for backward compat
214→  const id = userId || viewerId;
215→  if (!id || typeof id !== 'string') {
216→    return res.status(400).json({ error: 'userId required' });
217→  }
218→  if (!text || typeof text !== 'string' || text.trim().length === 0) {
219→    return res.status(400).json({ error: 'text required' });
220→  }
221→
222→  const sanitizedText = text.trim().slice(0, 500);
223→  const name = (typeof displayName === 'string' && displayName.trim())
224→    ? displayName.trim().slice(0, 30)
225→    : 'Anonymous';
226→  const userRole = role === 'admin' ? 'admin' : 'member';
227→  const avatar = typeof avatarUrl === 'string' ? avatarUrl : null;
228→
229→  downstream.broadcastChat(id, name, sanitizedText, userRole, avatar);
230→  return res.json({ sent: true });
231→});
232→
233→// Start
234→httpServer.listen(PORT, () => {
235→  console.log(`[bridge] PianoQuest Bridge Relay listening on :${PORT}`);
236→  console.log(`[bridge] WebSocket (viewers): ws://localhost:${PORT}/ws`);
237→  console.log(`[bridge] WebSocket (members): ws://localhost:${PORT}/ws/play`);
238→  console.log(`[bridge] Status:    http://localhost:${PORT}/api/status`);
239→  console.log(`[bridge] Play:      http://localhost:${PORT}/api/play/status`);
240→  upstream.start();
241→});
242→
243→// Graceful shutdown
244→function shutdown() {
245→  console.log('[bridge] Shutting down...');
246→  upstream.stop();
247→  memberUpstream.close();
248→  downstream.close();
249→  httpServer.close(() => process.exit(0));
250→  setTimeout(() => process.exit(1), 5000);
251→}
252→
253→process.on('SIGTERM', shutdown);
254→process.on('SIGINT', shutdown);
