  1→import WebSocket from 'ws';
  2→import { UpstreamMessage, StreamState } from './types';
  3→
  4→const UPSTREAM_URL = 'ws://127.0.0.1:3490/ws';
  5→const RECONNECT_INTERVAL = 5000;
  6→
  7→export class UpstreamClient {
  8→  private ws: WebSocket | null = null;
  9→  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 10→  private state: StreamState = {
 11→    live: false,
 12→    app: null,
 13→    version: null,
 14→    screen: null,
 15→    midiDevice: null,
 16→    connectedAt: null,
 17→    lastHeartbeat: null,
 18→  };
 19→
 20→  private onMessage: ((msg: UpstreamMessage) => void) | null = null;
 21→  private onStateChange: ((state: StreamState) => void) | null = null;
 22→
 23→  constructor(
 24→    onMessage: (msg: UpstreamMessage) => void,
 25→    onStateChange: (state: StreamState) => void,
 26→  ) {
 27→    this.onMessage = onMessage;
 28→    this.onStateChange = onStateChange;
 29→  }
 30→
 31→  getState(): StreamState {
 32→    return { ...this.state };
 33→  }
 34→
 35→  start(): void {
 36→    this.connect();
 37→  }
 38→
 39→  stop(): void {
 40→    if (this.reconnectTimer) {
 41→      clearTimeout(this.reconnectTimer);
 42→      this.reconnectTimer = null;
 43→    }
 44→    if (this.ws) {
 45→      this.ws.removeAllListeners();
 46→      this.ws.close();
 47→      this.ws = null;
 48→    }
 49→  }
 50→
 51→  private connect(): void {
 52→    if (this.ws) {
 53→      this.ws.removeAllListeners();
 54→      this.ws.close();
 55→      this.ws = null;
 56→    }
 57→
 58→    console.log(`[upstream] Connecting to ${UPSTREAM_URL}...`);
 59→    this.ws = new WebSocket(UPSTREAM_URL);
 60→
 61→    this.ws.on('open', () => {
 62→      console.log('[upstream] Connected to PianoQuest');
 63→      this.state.live = true;
 64→      this.state.connectedAt = Date.now();
 65→      this.onStateChange?.(this.getState());
 66→    });
 67→
 68→    this.ws.on('message', (data) => {
 69→      try {
 70→        const msg: UpstreamMessage = JSON.parse(data.toString());
 71→        if (msg.type === 'status') {
 72→          this.state.app = msg.app;
 73→          this.state.version = msg.version;
 74→          this.state.screen = msg.screen;
 75→          this.state.midiDevice = msg.midiDevice;
 76→          this.onStateChange?.(this.getState());
 77→        } else if (msg.type === 'heartbeat') {
 78→          this.state.lastHeartbeat = Date.now();
 79→        }
 80→        this.onMessage?.(msg);
 81→      } catch (err) {
 82→        console.error('[upstream] Failed to parse message:', err);
 83→      }
 84→    });
 85→
 86→    this.ws.on('close', () => {
 87→      console.log('[upstream] Disconnected from PianoQuest');
 88→      this.ws = null;
 89→      if (this.state.live) {
 90→        this.state.live = false;
 91→        this.state.connectedAt = null;
 92→        this.onStateChange?.(this.getState());
 93→      }
 94→      this.scheduleReconnect();
 95→    });
 96→
 97→    this.ws.on('error', (err) => {
 98→      // ECONNREFUSED is expected when PianoQuest isn't running — don't spam logs
 99→      const code = (err as NodeJS.ErrnoException).code;
100→      if (code !== 'ECONNREFUSED') {
101→        console.error('[upstream] Error:', err.message);
102→      }
103→    });
104→  }
105→
106→  private scheduleReconnect(): void {
107→    if (this.reconnectTimer) return;
108→    this.reconnectTimer = setTimeout(() => {
109→      this.reconnectTimer = null;
110→      this.connect();
111→    }, RECONNECT_INTERVAL);
112→  }
113→}
