  1→import WebSocket, { WebSocketServer } from 'ws';
  2→import { IncomingMessage } from 'http';
  3→import { randomUUID } from 'crypto';
  4→import {
  5→  UpstreamMessage,
  6→  DownstreamMessage,
  7→  StreamStatusMessage,
  8→  ViewerCountMessage,
  9→  ChatMessage,
 10→  PlayerStatusMessage,
 11→  StreamState,
 12→} from './types';
 13→
 14→interface Viewer {
 15→  ws: WebSocket;
 16→  id: string;
 17→  displayName: string;
 18→  joinedAt: number;
 19→}
 20→
 21→export class DownstreamServer {
 22→  private wss: WebSocketServer;
 23→  private viewers = new Map<WebSocket, Viewer>();
 24→  private getState: () => StreamState;
 25→  private onViewerCountChange: ((count: number) => void) | null = null;
 26→
 27→  constructor(
 28→    wss: WebSocketServer,
 29→    getState: () => StreamState,
 30→    onViewerCountChange?: (count: number) => void,
 31→  ) {
 32→    this.getState = getState;
 33→    this.onViewerCountChange = onViewerCountChange ?? null;
 34→
 35→    this.wss = wss;
 36→
 37→    this.wss.on('connection', (ws: WebSocket, _req: IncomingMessage) => {
 38→      const viewer: Viewer = {
 39→        ws,
 40→        id: randomUUID(),
 41→        displayName: '',
 42→        joinedAt: Date.now(),
 43→      };
 44→      this.viewers.set(ws, viewer);
 45→      const count = this.viewers.size;
 46→      console.log(`[downstream] Viewer ${viewer.id.slice(0, 8)} connected (${count} total)`);
 47→
 48→      // Send current stream status to new viewer
 49→      this.sendTo(ws, this.buildStreamStatus());
 50→      this.broadcastViewerCount();
 51→
 52→      ws.on('close', () => {
 53→        const v = this.viewers.get(ws);
 54→        this.viewers.delete(ws);
 55→        const remaining = this.viewers.size;
 56→        console.log(`[downstream] Viewer ${v?.id.slice(0, 8) ?? '?'} disconnected (${remaining} total)`);
 57→        this.broadcastViewerCount();
 58→      });
 59→
 60→      ws.on('error', (err) => {
 61→        console.error('[downstream] Viewer error:', err.message);
 62→        this.viewers.delete(ws);
 63→      });
 64→    });
 65→  }
 66→
 67→  getViewerCount(): number {
 68→    return this.viewers.size;
 69→  }
 70→
 71→  relayUpstreamMessage(msg: UpstreamMessage): void {
 72→    if (msg.type === 'midi') {
 73→      const downstream: DownstreamMessage = {
 74→        ...msg,
 75→        serverTimestampMs: Date.now(),
 76→      };
 77→      this.broadcast(downstream);
 78→    }
 79→  }
 80→
 81→  broadcastStreamStatus(): void {
 82→    this.broadcast(this.buildStreamStatus());
 83→  }
 84→
 85→  broadcastPlayerStatus(msg: PlayerStatusMessage): void {
 86→    this.broadcast(msg);
 87→  }
 88→
 89→  broadcastChat(userId: string, displayName: string, text: string, role: 'admin' | 'member' = 'member', avatarUrl: string | null = null): void {
 90→    const msg: ChatMessage = {
 91→      type: 'chat',
 92→      userId,
 93→      displayName,
 94→      text,
 95→      role,
 96→      avatarUrl,
 97→      timestampMs: Date.now(),
 98→    };
 99→    this.broadcast(msg);
100→  }
101→
102→  private broadcastViewerCount(): void {
103→    const msg: ViewerCountMessage = {
104→      type: 'viewerCount',
105→      count: this.viewers.size,
106→    };
107→    this.broadcast(msg);
108→    this.onViewerCountChange?.(this.viewers.size);
109→  }
110→
111→  private buildStreamStatus(): StreamStatusMessage {
112→    const state = this.getState();
113→    return {
114→      type: 'streamStatus',
115→      live: state.live,
116→      app: state.app,
117→      viewers: this.viewers.size,
118→      uptimeMs: state.connectedAt ? Date.now() - state.connectedAt : 0,
119→    };
120→  }
121→
122→  private broadcast(msg: DownstreamMessage): void {
123→    const data = JSON.stringify(msg);
124→    for (const [ws] of this.viewers) {
125→      if (ws.readyState === WebSocket.OPEN) {
126→        ws.send(data);
127→      }
128→    }
129→  }
130→
131→  private sendTo(ws: WebSocket, msg: DownstreamMessage): void {
132→    if (ws.readyState === WebSocket.OPEN) {
133→      ws.send(JSON.stringify(msg));
134→    }
135→  }
136→
137→  close(): void {
138→    this.wss.close();
139→  }
140→}
