  1→import WebSocket, { WebSocketServer } from 'ws';
  2→import { IncomingMessage } from 'http';
  3→import { createClient, SupabaseClient } from '@supabase/supabase-js';
  4→import {
  5→  MidiMessage,
  6→  AuthMessage,
  7→  AuthResultMessage,
  8→  MemberMessage,
  9→} from './types';
 10→import { PlayerManager } from './player-manager';
 11→
 12→const AUTH_TIMEOUT_MS = 10_000; // 10 seconds to send auth message
 13→
 14→export class MemberUpstreamServer {
 15→  private wss: WebSocketServer;
 16→  private supabase: SupabaseClient;
 17→  private playerManager: PlayerManager;
 18→  private onMidiMessage: (msg: MidiMessage) => void;
 19→  // Map ws → userId for authenticated connections
 20→  private authenticated = new Map<WebSocket, string>();
 21→
 22→  constructor(
 23→    wss: WebSocketServer,
 24→    playerManager: PlayerManager,
 25→    onMidiMessage: (msg: MidiMessage) => void,
 26→  ) {
 27→    this.playerManager = playerManager;
 28→    this.onMidiMessage = onMidiMessage;
 29→
 30→    const supabaseUrl = process.env.SUPABASE_URL;
 31→    const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
 32→    if (!supabaseUrl || !supabaseKey) {
 33→      throw new Error('SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY must be set');
 34→    }
 35→    this.supabase = createClient(supabaseUrl, supabaseKey);
 36→
 37→    this.wss = wss;
 38→
 39→    this.wss.on('connection', (ws: WebSocket, _req: IncomingMessage) => {
 40→      console.log('[member-upstream] New connection on /ws/play');
 41→
 42→      // Auth timeout — disconnect if no auth message within 10 seconds
 43→      const authTimeout = setTimeout(() => {
 44→        if (!this.authenticated.has(ws)) {
 45→          this.sendAuth(ws, { type: 'authResult', success: false, error: 'Auth timeout' });
 46→          ws.close(1008, 'Auth timeout');
 47→        }
 48→      }, AUTH_TIMEOUT_MS);
 49→
 50→      ws.on('message', async (data) => {
 51→        try {
 52→          const msg: MemberMessage = JSON.parse(data.toString());
 53→
 54→          if (msg.type === 'auth') {
 55→            clearTimeout(authTimeout);
 56→            await this.handleAuth(ws, msg);
 57→            return;
 58→          }
 59→
 60→          if (msg.type === 'midi') {
 61→            this.handleMidi(ws, msg);
 62→            return;
 63→          }
 64→        } catch (err) {
 65→          console.error('[member-upstream] Failed to parse message:', err);
 66→        }
 67→      });
 68→
 69→      ws.on('close', () => {
 70→        clearTimeout(authTimeout);
 71→        const userId = this.authenticated.get(ws);
 72→        if (userId) {
 73→          console.log(`[member-upstream] Member ${userId.slice(0, 8)} disconnected`);
 74→          this.playerManager.handleMemberDisconnect(ws);
 75→          this.authenticated.delete(ws);
 76→        }
 77→      });
 78→
 79→      ws.on('error', (err) => {
 80→        console.error('[member-upstream] WebSocket error:', err.message);
 81→        clearTimeout(authTimeout);
 82→        this.authenticated.delete(ws);
 83→      });
 84→    });
 85→  }
 86→
 87→  private async handleAuth(ws: WebSocket, msg: AuthMessage): Promise<void> {
 88→    try {
 89→      // Validate JWT via Supabase
 90→      const { data: { user }, error } = await this.supabase.auth.getUser(msg.token);
 91→
 92→      if (error || !user) {
 93→        this.sendAuth(ws, { type: 'authResult', success: false, error: 'Invalid token' });
 94→        ws.close(1008, 'Invalid token');
 95→        return;
 96→      }
 97→
 98→      // Check play eligibility via Supabase RPC
 99→      const { data: eligibility } = await this.supabase.rpc('check_play_eligibility', { p_user_id: user.id });
100→      if (!eligibility?.eligible) {
101→        this.sendAuth(ws, { type: 'authResult', success: false, error: eligibility?.reason || 'Not eligible' });
102→        ws.close(1008, 'Not eligible');
103→        return;
104→      }
105→
106→      const displayName = eligibility.display_name || user.email?.split('@')[0] || 'Member';
107→      const avatarUrl = eligibility.avatar_url || null;
108→
109→      this.authenticated.set(ws, user.id);
110→
111→      this.sendAuth(ws, {
112→        type: 'authResult',
113→        success: true,
114→        userId: user.id,
115→        displayName,
116→      });
117→
118→      // Auto-request to play on auth
119→      const result = this.playerManager.requestPlay(user.id, displayName, avatarUrl, ws);
120→
121→      if (result.playing) {
122→        console.log(`[member-upstream] Member ${user.id.slice(0, 8)} (${displayName}) is now playing`);
123→      } else {
124→        console.log(`[member-upstream] Member ${user.id.slice(0, 8)} (${displayName}) queued at position ${result.queuePosition}`);
125→        if (ws.readyState === WebSocket.OPEN) {
126→          ws.send(JSON.stringify({
127→            type: 'queuePosition',
128→            position: result.queuePosition,
129→            totalInQueue: result.queuePosition,
130→          }));
131→        }
132→      }
133→    } catch (err) {
134→      console.error('[member-upstream] Auth error:', err);
135→      this.sendAuth(ws, { type: 'authResult', success: false, error: 'Auth failed' });
136→      ws.close(1008, 'Auth failed');
137→    }
138→  }
139→
140→  private handleMidi(ws: WebSocket, msg: MidiMessage): void {
141→    const userId = this.authenticated.get(ws);
142→    if (!userId) {
143→      // Not authenticated — ignore
144→      return;
145→    }
146→
147→    // Only relay if this user is the current player
148→    if (!this.playerManager.isCurrentPlayer(userId)) {
149→      return;
150→    }
151→
152→    // Relay to all viewers via the onMidiMessage callback
153→    this.onMidiMessage(msg);
154→  }
155→
156→  private sendAuth(ws: WebSocket, msg: AuthResultMessage): void {
157→    if (ws.readyState === WebSocket.OPEN) {
158→      ws.send(JSON.stringify(msg));
159→    }
160→  }
161→
