  1→import { MidiStreamEvent, StreamStatusEvent, ViewerCountEvent, ChatEvent } from './types';
  2→
  3→// SSE endpoint — goes through Next.js API route, avoids Traefik WS proxy
  4→const PROD_SSE_URL = '/api/live/stream';
  5→const DEV_WS_URL = 'ws://localhost:3491/ws';
  6→const MAX_BACKOFF = 30000;
  7→const INITIAL_BACKOFF = 1000;
  8→
  9→export interface LiveClientCallbacks {
 10→  onMidi?: (event: MidiStreamEvent) => void;
 11→  onStreamStatus?: (event: StreamStatusEvent) => void;
 12→  onViewerCount?: (event: ViewerCountEvent) => void;
 13→  onChat?: (event: ChatEvent) => void;
 14→  onConnectionChange?: (connected: boolean) => void;
 15→}
 16→
 17→export class PianoQuestLiveClient {
 18→  private eventSource: EventSource | null = null;
 19→  private ws: WebSocket | null = null;
 20→  private callbacks: LiveClientCallbacks;
 21→  private isDev: boolean;
 22→  private reconnectTimer: ReturnType<typeof setTimeout> | null = null;
 23→  private backoff = INITIAL_BACKOFF;
 24→  private intentionalClose = false;
 25→
 26→  constructor(callbacks: LiveClientCallbacks, isDev = false) {
 27→    this.callbacks = callbacks;
 28→    this.isDev = isDev;
 29→  }
 30→
 31→  connect(): void {
 32→    this.intentionalClose = false;
 33→    if (this.isDev) {
 34→      this.connectWS();
 35→    } else {
 36→      this.connectSSE();
 37→    }
 38→  }
 39→
 40→  disconnect(): void {
 41→    this.intentionalClose = true;
 42→    if (this.reconnectTimer) {
 43→      clearTimeout(this.reconnectTimer);
 44→      this.reconnectTimer = null;
 45→    }
 46→    if (this.eventSource) {
 47→      this.eventSource.close();
 48→      this.eventSource = null;
 49→    }
 50→    if (this.ws) {
 51→      this.ws.close();
 52→      this.ws = null;
 53→    }
 54→  }
 55→
 56→  isConnected(): boolean {
 57→    if (this.isDev) {
 58→      return this.ws?.readyState === WebSocket.OPEN;
 59→    }
 60→    return this.eventSource?.readyState === EventSource.OPEN;
 61→  }
 62→
 63→  // Production: SSE via Next.js API route
 64→  private connectSSE(): void {
 65→    if (this.eventSource) {
 66→      this.eventSource.close();
 67→      this.eventSource = null;
 68→    }
 69→
 70→    try {
 71→      this.eventSource = new EventSource(PROD_SSE_URL);
 72→    } catch {
 73→      this.scheduleReconnect();
 74→      return;
 75→    }
 76→
 77→    this.eventSource.addEventListener('connected', () => {
 78→      this.backoff = INITIAL_BACKOFF;
 79→      this.callbacks.onConnectionChange?.(true);
 80→    });
 81→
 82→    this.eventSource.addEventListener('midi', (e) => {
 83→      try {
 84→        const msg: MidiStreamEvent = JSON.parse(e.data);
 85→        this.callbacks.onMidi?.(msg);
 86→      } catch {}
 87→    });
 88→
 89→    this.eventSource.addEventListener('streamStatus', (e) => {
 90→      try {
 91→        const msg: StreamStatusEvent = JSON.parse(e.data);
 92→        this.callbacks.onStreamStatus?.(msg);
 93→      } catch {}
 94→    });
 95→
 96→    this.eventSource.addEventListener('viewerCount', (e) => {
 97→      try {
 98→        const msg: ViewerCountEvent = JSON.parse(e.data);
 99→        this.callbacks.onViewerCount?.(msg);
100→      } catch {}
101→    });
102→
103→    this.eventSource.addEventListener('chat', (e) => {
104→      try {
105→        const msg: ChatEvent = JSON.parse(e.data);
106→        this.callbacks.onChat?.(msg);
107→      } catch {}
108→    });
109→
110→    this.eventSource.addEventListener('disconnected', () => {
111→      this.callbacks.onConnectionChange?.(false);
112→      this.eventSource?.close();
113→      this.eventSource = null;
114→      if (!this.intentionalClose) {
115→        this.scheduleReconnect();
116→      }
117→    });
118→
119→    this.eventSource.onerror = () => {
120→      this.callbacks.onConnectionChange?.(false);
121→      this.eventSource?.close();
122→      this.eventSource = null;
123→      if (!this.intentionalClose) {
124→        this.scheduleReconnect();
125→      }
126→    };
127→  }
128→
129→  // Dev: direct WebSocket to bridge
130→  private connectWS(): void {
131→    if (this.ws) {
132→      this.ws.close();
133→      this.ws = null;
134→    }
135→
136→    try {
137→      this.ws = new WebSocket(DEV_WS_URL);
138→    } catch {
139→      this.scheduleReconnect();
140→      return;
141→    }
142→
143→    this.ws.onopen = () => {
144→      this.backoff = INITIAL_BACKOFF;
145→      this.callbacks.onConnectionChange?.(true);
146→    };
147→
148→    this.ws.onmessage = (event) => {
149→      try {
150→        const msg = JSON.parse(event.data as string);
151→        switch (msg.type) {
152→          case 'midi':
153→            this.callbacks.onMidi?.(msg);
154→            break;
155→          case 'streamStatus':
156→            this.callbacks.onStreamStatus?.(msg);
157→            break;
158→          case 'viewerCount':
159→            this.callbacks.onViewerCount?.(msg);
160→            break;
161→          case 'chat':
162→            this.callbacks.onChat?.(msg);
163→            break;
164→        }
165→      } catch {}
166→    };
167→
168→    this.ws.onclose = () => {
169→      this.ws = null;
170→      this.callbacks.onConnectionChange?.(false);
171→      if (!this.intentionalClose) {
172→        this.scheduleReconnect();
173→      }
174→    };
175→
176→    this.ws.onerror = () => {};
177→  }
178→
179→  private scheduleReconnect(): void {
180→    if (this.reconnectTimer || this.intentionalClose) return;
181→    this.reconnectTimer = setTimeout(() => {
182→      this.reconnectTimer = null;
183→      this.connect();
184→    }, this.backoff);
185→    this.backoff = Math.min(this.backoff * 2, MAX_BACKOFF);
186→  }
187→}
