  3→import { useRef, useEffect, useCallback } from 'react';
  4→import { ActiveNote } from '../../lib/streaming/types';
  5→
  6→const TOTAL_KEYS = 88;
  7→const FIRST_MIDI = 21; // A0
  8→const WHITE_KEYS_COUNT = 52;
  9→const ACCENT = '#0891b2';
 10→
 11→// Map of which notes are black keys (0=C, 1=C#, etc.)
 12→const BLACK_KEY_PATTERN = [false, true, false, true, false, false, true, false, true, false, true, false];
 13→
 14→interface KeyInfo {
 15→  midi: number;
 16→  isBlack: boolean;
 17→  whiteIndex: number; // index among white keys (for positioning)
 18→}
 19→
 20→function buildKeyboard(): KeyInfo[] {
 21→  const keys: KeyInfo[] = [];
 22→  let whiteIdx = 0;
 23→  for (let i = 0; i < TOTAL_KEYS; i++) {
 24→    const midi = FIRST_MIDI + i;
 25→    const noteInOctave = midi % 12;
 26→    const isBlack = BLACK_KEY_PATTERN[noteInOctave];
 27→    keys.push({ midi, isBlack, whiteIndex: isBlack ? whiteIdx - 1 : whiteIdx });
 28→    if (!isBlack) whiteIdx++;
 29→  }
 30→  return keys;
 31→}
 32→
 33→const KEYBOARD = buildKeyboard();
 34→
 35→interface PianoVisualizerProps {
 36→  activeNotes: Map<number, ActiveNote>;
 37→  width?: number;
 38→  height?: number;
 39→}
 40→
 41→export function PianoVisualizer({ activeNotes, width, height }: PianoVisualizerProps) {
 42→  const canvasRef = useRef<HTMLCanvasElement>(null);
 43→  const containerRef = useRef<HTMLDivElement>(null);
 44→  const sizeRef = useRef({ w: width ?? 800, h: height ?? 160 });
 45→
 46→  const draw = useCallback(() => {
 47→    const canvas = canvasRef.current;
 48→    if (!canvas) return;
 49→    const ctx = canvas.getContext('2d');
 50→    if (!ctx) return;
 51→
 52→    const W = canvas.width;
 53→    const H = canvas.height;
 54→    const dpr = window.devicePixelRatio || 1;
 55→    const whiteKeyW = (W / dpr) / WHITE_KEYS_COUNT;
 56→    const blackKeyW = whiteKeyW * 0.6;
 57→    const blackKeyH = (H / dpr) * 0.62;
 58→
 59→    ctx.save();
 60→    ctx.scale(dpr, dpr);
 61→    ctx.clearRect(0, 0, W / dpr, H / dpr);
 62→
 63→    // Draw white keys first
 64→    for (const key of KEYBOARD) {
 65→      if (key.isBlack) continue;
 66→      const x = key.whiteIndex * whiteKeyW;
 67→      const active = activeNotes.get(key.midi);
 68→
 69→      if (active) {
 70→        const opacity = 0.4 + (active.velocity / 127) * 0.6;
 71→        ctx.fillStyle = `rgba(8, 145, 178, ${opacity})`;
 72→        ctx.shadowColor = ACCENT;
 73→        ctx.shadowBlur = 12;
 74→      } else {
 75→        ctx.fillStyle = 'rgba(255, 255, 255, 0.08)';
 76→        ctx.shadowColor = 'transparent';
 77→        ctx.shadowBlur = 0;
 78→      }
 79→
 80→      ctx.fillRect(x + 0.5, 0, whiteKeyW - 1, H / dpr - 1);
 81→      ctx.strokeStyle = 'rgba(255, 255, 255, 0.12)';
 82→      ctx.lineWidth = 0.5;
 83→      ctx.strokeRect(x + 0.5, 0, whiteKeyW - 1, H / dpr - 1);
 84→    }
 85→
 86→    // Draw black keys on top
 87→    ctx.shadowBlur = 0;
 88→    for (const key of KEYBOARD) {
 89→      if (!key.isBlack) continue;
 90→      const x = (key.whiteIndex + 1) * whiteKeyW - blackKeyW / 2;
 91→      const active = activeNotes.get(key.midi);
 92→
 93→      if (active) {
 94→        const opacity = 0.5 + (active.velocity / 127) * 0.5;
 95→        ctx.fillStyle = `rgba(8, 145, 178, ${opacity})`;
 96→        ctx.shadowColor = ACCENT;
 97→        ctx.shadowBlur = 10;
 98→      } else {
 99→        ctx.fillStyle = '#111';
100→        ctx.shadowColor = 'transparent';
101→        ctx.shadowBlur = 0;
102→      }
103→
104→      ctx.fillRect(x, 0, blackKeyW, blackKeyH);
105→      ctx.strokeStyle = 'rgba(255, 255, 255, 0.08)';
106→      ctx.lineWidth = 0.5;
107→      ctx.strokeRect(x, 0, blackKeyW, blackKeyH);
108→    }
109→
110→    ctx.restore();
111→  }, [activeNotes]);
112→
113→  // Resize observer for responsive canvas
114→  useEffect(() => {
115→    if (width) return; // skip if explicit width set
116→    const container = containerRef.current;
117→    if (!container) return;
118→
119→    const observer = new ResizeObserver((entries) => {
120→      for (const entry of entries) {
121→        const w = entry.contentRect.width;
122→        const h = Math.max(120, w * 0.18);
123→        sizeRef.current = { w, h };
124→        const canvas = canvasRef.current;
125→        if (canvas) {
126→          const dpr = window.devicePixelRatio || 1;
127→          canvas.width = w * dpr;
128→          canvas.height = h * dpr;
129→          canvas.style.width = `${w}px`;
130→          canvas.style.height = `${h}px`;
131→        }
132→      }
133→    });
134→    observer.observe(container);
135→    return () => observer.disconnect();
136→  }, [width]);
137→
138→  // Set explicit size
139→  useEffect(() => {
140→    if (!width || !height) return;
141→    const canvas = canvasRef.current;
142→    if (!canvas) return;
143→    const dpr = window.devicePixelRatio || 1;
144→    canvas.width = width * dpr;
145→    canvas.height = height * dpr;
146→    canvas.style.width = `${width}px`;
147→    canvas.style.height = `${height}px`;
148→  }, [width, height]);
149→
150→  // Redraw on active notes change
151→  useEffect(() => {
152→    draw();
153→  }, [draw]);
154→
155→  return (
156→    <div
157→      ref={containerRef}
158→      style={{
159→        width: width ? `${width}px` : '100%',
160→        borderRadius: 8,
161→        overflow: 'hidden',
162→        background: 'rgba(255, 255, 255, 0.04)',
163→        border: '1px solid rgba(255, 255, 255, 0.08)',
164→      }}
165→    >
166→      <canvas
167→        ref={canvasRef}
168→        style={{
169→          display: 'block',
170→          width: width ? `${width}px` : '100%',
171→          height: height ? `${height}px` : 'auto',
172→        }}
173→      />
174→    </div>
175→  );
176→}
