  5→
  6→const TOTAL_KEYS = 88;
  7→const FIRST_MIDI = 21; // A0
  8→const WHITE_KEYS_COUNT = 52;
  9→
 10→const BLACK_KEY_PATTERN = [false, true, false, true, false, false, true, false, true, false, true, false];
 11→
 12→interface KeyInfo {
 13→  midi: number;
 14→  isBlack: boolean;
 15→  whiteIndex: number;
 16→}
 17→
 18→function buildKeyboard(): KeyInfo[] {
 19→  const keys: KeyInfo[] = [];
 20→  let whiteIdx = 0;
 21→  for (let i = 0; i < TOTAL_KEYS; i++) {
 22→    const midi = FIRST_MIDI + i;
 23→    const noteInOctave = midi % 12;
 24→    const isBlack = BLACK_KEY_PATTERN[noteInOctave];
 25→    keys.push({ midi, isBlack, whiteIndex: isBlack ? whiteIdx - 1 : whiteIdx });
 26→    if (!isBlack) whiteIdx++;
 27→  }
