 31→const KEYBOARD = buildKeyboard();
 32→
 33→// O(1) lookup by MIDI number for the draw loop
 34→const KEY_BY_MIDI = new Map<number, KeyInfo>();
 35→for (const k of KEYBOARD) KEY_BY_MIDI.set(k.midi, k);
 36→
 37→// Dynamics color scale: ppp (blue) → pp → p → mp → mf → f → ff → fff (purple)
 38→const DYNAMICS_COLORS = [
 39→  { vel: 0, r: 59, g: 130, b: 246 },   // ppp — blue
 40→  { vel: 18, r: 59, g: 130, b: 246 },   // ppp
 41→  { vel: 36, r: 6, g: 182, b: 212 },    // pp — cyan
 42→  { vel: 54, r: 16, g: 185, b: 129 },   // p — emerald
 43→  { vel: 72, r: 234, g: 179, b: 8 },    // mp — amber
 44→  { vel: 90, r: 249, g: 115, b: 22 },   // mf — orange
 45→  { vel: 100, r: 239, g: 68, b: 68 },   // f — red
 46→  { vel: 112, r: 236, g: 72, b: 153 },  // ff — pink
 47→  { vel: 127, r: 168, g: 85, b: 247 },  // fff — purple
 48→];
 49→
 50→const DYNAMICS_LABELS = [
 51→  { vel: 0, label: 'ppp' },
 52→  { vel: 18, label: 'pp' },
 53→  { vel: 36, label: 'p' },
 54→  { vel: 54, label: 'mp' },
 55→  { vel: 72, label: 'mf' },
 56→  { vel: 90, label: 'f' },
 57→  { vel: 112, label: 'ff' },
 58→  { vel: 127, label: 'fff' },
 59→];
 60→
 61→function dynamicsColor(velocity: number): string {
 62→  if (velocity <= DYNAMICS_COLORS[0].vel) {
 63→    const c = DYNAMICS_COLORS[0];
 64→    return `rgb(${c.r}, ${c.g}, ${c.b})`;
 65→  }
 66→  for (let i = 1; i < DYNAMICS_COLORS.length; i++) {
 67→    if (velocity <= DYNAMICS_COLORS[i].vel) {
 68→      const lo = DYNAMICS_COLORS[i - 1];
 69→      const hi = DYNAMICS_COLORS[i];
 70→      const t = (velocity - lo.vel) / (hi.vel - lo.vel);
 71→      const r = Math.round(lo.r + (hi.r - lo.r) * t);
 72→      const g = Math.round(lo.g + (hi.g - lo.g) * t);
 73→      const b = Math.round(lo.b + (hi.b - lo.b) * t);
 74→      return `rgb(${r}, ${g}, ${b})`;
 75→    }
 76→  }
 77→  const c = DYNAMICS_COLORS[DYNAMICS_COLORS.length - 1];
 78→  return `rgb(${c.r}, ${c.g}, ${c.b})`;
 79→}
 80→
 81→function dynamicsColorAlpha(velocity: number, alpha: number): string {
 82→  if (velocity <= DYNAMICS_COLORS[0].vel) {
 83→    const c = DYNAMICS_COLORS[0];
 84→    return `rgba(${c.r}, ${c.g}, ${c.b}, ${alpha})`;
 85→  }
 86→  for (let i = 1; i < DYNAMICS_COLORS.length; i++) {
 87→    if (velocity <= DYNAMICS_COLORS[i].vel) {
 88→      const lo = DYNAMICS_COLORS[i - 1];
 89→      const hi = DYNAMICS_COLORS[i];
 90→      const t = (velocity - lo.vel) / (hi.vel - lo.vel);
 91→      const r = Math.round(lo.r + (hi.r - lo.r) * t);
 92→      const g = Math.round(lo.g + (hi.g - lo.g) * t);
 93→      const b = Math.round(lo.b + (hi.b - lo.b) * t);
 94→      return `rgba(${r}, ${g}, ${b}, ${alpha})`;
 95→    }
 96→  }
 97→  const c = DYNAMICS_COLORS[DYNAMICS_COLORS.length - 1];
 98→  return `rgba(${c.r}, ${c.g}, ${c.b}, ${alpha})`;
 99→}
