101→interface PianoRollCanvasProps {
102→  activeNotes: Map<number, ActiveNote>;
103→  noteHistory: NoteHistory[];
104→  windowDurationMs?: number;
105→  bpm?: number;
106→}
107→
108→const WATERFALL_BG = '#1A1A2E';
109→const LANE_LINE = '#24243C';
110→const OCTAVE_LINE = '#2A2A4A';
111→const BLACK_LANE_BG = '#0F1430';
112→const WATERFALL_RATIO = 0.78;
113→const DYNAMICS_RATIO = 0.22;
114→
115→export function PianoRollCanvas({
116→  activeNotes,
117→  noteHistory,
118→  windowDurationMs = 5000,
119→  bpm = 120,
120→}: PianoRollCanvasProps) {
121→  const canvasRef = useRef<HTMLCanvasElement>(null);
122→  const containerRef = useRef<HTMLDivElement>(null);
123→  const sizeRef = useRef({ w: 800, h: 400 });
124→  const rafRef = useRef<number>(0);
125→
126→  // Store props in refs so the rAF loop doesn't cause callback re-creation
127→  const activeNotesRef = useRef(activeNotes);
128→  const noteHistoryRef = useRef(noteHistory);
129→  activeNotesRef.current = activeNotes;
130→  noteHistoryRef.current = noteHistory;
131→
132→  const draw = useCallback(() => {
133→    const canvas = canvasRef.current;
134→    if (!canvas) return;
135→    const ctx = canvas.getContext('2d');
136→    if (!ctx) return;
137→
138→    const dpr = window.devicePixelRatio || 1;
139→    const W = sizeRef.current.w;
140→    const H = sizeRef.current.h;
141→    const now = Date.now();
142→    const currentNotes = activeNotesRef.current;
143→    const currentHistory = noteHistoryRef.current;
144→
145→    ctx.save();
146→    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
147→
148→    const waterfallH = H * WATERFALL_RATIO;
149→    const dynamicsH = H * DYNAMICS_RATIO;
150→    const dynamicsY = waterfallH;
151→
152→    const whiteKeyW = W / WHITE_KEYS_COUNT;
153→    const blackKeyW = whiteKeyW * 0.65;
154→    const pixelsPerMs = waterfallH / windowDurationMs;
155→
156→    // Beat grid timing
157→    const msPerBeat = 60000 / bpm;
158→
159→    // === WATERFALL ZONE ===
160→    ctx.fillStyle = WATERFALL_BG;
161→    ctx.fillRect(0, 0, W, waterfallH);
162→
163→    // Draw lane lines (vertical separators for each white key)
164→    ctx.strokeStyle = LANE_LINE;
165→    ctx.lineWidth = 0.5;
166→    for (let i = 0; i <= WHITE_KEYS_COUNT; i++) {
167→      const x = i * whiteKeyW;
168→      ctx.beginPath();
169→      ctx.moveTo(x, 0);
170→      ctx.lineTo(x, waterfallH);
171→      ctx.stroke();
172→    }
173→
174→    // Draw octave lines (thicker, at C notes)
175→    ctx.strokeStyle = OCTAVE_LINE;
176→    ctx.lineWidth = 1;
177→    for (const key of KEYBOARD) {
178→      if (key.isBlack) continue;
179→      if (key.midi % 12 === 0) { // C notes
180→        const x = key.whiteIndex * whiteKeyW;
181→        ctx.beginPath();
182→        ctx.moveTo(x, 0);
183→        ctx.lineTo(x, waterfallH);
184→        ctx.stroke();
185→      }
186→    }
187→
188→    // Shade black key lanes
189→    for (const key of KEYBOARD) {
190→      if (!key.isBlack) continue;
191→      const x = (key.whiteIndex + 1) * whiteKeyW - blackKeyW / 2;
192→      ctx.fillStyle = BLACK_LANE_BG;
193→      ctx.fillRect(x, 0, blackKeyW, waterfallH);
194→    }
195→
196→    // Beat grid (horizontal lines)
197→    const firstBeatOffset = now % msPerBeat;
198→    const totalBeats = Math.ceil(windowDurationMs / msPerBeat) + 1;
199→    ctx.lineWidth = 0.5;
200→    for (let i = 0; i < totalBeats; i++) {
201→      const beatTimeAgo = firstBeatOffset + i * msPerBeat;
202→      const y = waterfallH - beatTimeAgo * pixelsPerMs;
203→      if (y < 0 || y > waterfallH) continue;
204→
205→      const beatIndex = Math.round((now - beatTimeAgo) / msPerBeat);
206→      if (beatIndex % 4 === 0) {
207→        ctx.strokeStyle = 'rgba(255, 255, 255, 0.12)';
208→        ctx.lineWidth = 1;
209→      } else {
210→        ctx.strokeStyle = 'rgba(255, 255, 255, 0.05)';
211→        ctx.lineWidth = 0.5;
212→      }
213→      ctx.beginPath();
214→      ctx.moveTo(0, y);
215→      ctx.lineTo(W, y);
216→      ctx.stroke();
217→    }
218→
219→    // Draw note blocks — two passes: white keys first, then black keys
220→    const drawNoteBlocks = (blackOnly: boolean) => {
221→      for (const entry of currentHistory) {
222→        const keyInfo = KEY_BY_MIDI.get(entry.note);
223→        if (!keyInfo) continue;
224→        if (blackOnly !== keyInfo.isBlack) continue;
225→
226→        const ageStart = now - entry.startMs;
227→        const ageEnd = entry.endMs === 0 ? 0 : now - entry.endMs;
228→
229→        // Skip notes too old to be visible
230→        if (ageStart > windowDurationMs) continue;
231→
232→        // Bottom of note (noteOn time or playhead)
233→        const yBottom = entry.endMs === 0
234→          ? waterfallH // held — pinned to playhead
235→          : waterfallH - ageEnd * pixelsPerMs;
236→
237→        // Top of note (noteOn scrolling up)
238→        const yTop = waterfallH - ageStart * pixelsPerMs;
239→
240→        if (yBottom < 0 || yTop > waterfallH) continue;
241→
242→        const clampedTop = Math.max(0, yTop);
243→        const clampedBottom = Math.min(waterfallH, yBottom);
244→        const noteH = clampedBottom - clampedTop;
245→        if (noteH < 1) continue;
246→
247→        let noteX: number;
248→        let noteW: number;
249→        if (keyInfo.isBlack) {
250→          noteX = (keyInfo.whiteIndex + 1) * whiteKeyW - blackKeyW / 2;
251→          noteW = blackKeyW;
252→        } else {
253→          noteX = keyInfo.whiteIndex * whiteKeyW + 1;
254→          noteW = whiteKeyW - 2;
255→        }
256→
257→        // Darken black keys
258→        const color = dynamicsColor(entry.velocity);
259→        if (keyInfo.isBlack) {
260→          ctx.globalAlpha = 0.65;
261→        }
262→
263→        ctx.fillStyle = color;
264→        ctx.fillRect(noteX, clampedTop, noteW, noteH);
265→
266→        // Glow for high velocity
267→        if (entry.velocity > 100) {
268→          ctx.shadowColor = color;
269→          ctx.shadowBlur = 8;
270→          ctx.fillRect(noteX, clampedTop, noteW, noteH);
271→          ctx.shadowColor = 'transparent';
272→          ctx.shadowBlur = 0;
273→        }
274→
275→        // Top highlight
276→        const highlightAlpha = (entry.velocity / 127) * 0.3;
277→        ctx.fillStyle = `rgba(255, 255, 255, ${highlightAlpha})`;
278→        ctx.fillRect(noteX, clampedTop, noteW, Math.min(2, noteH));
279→
280→        ctx.globalAlpha = 1.0;
281→      }
282→    };
283→
284→    drawNoteBlocks(false); // white keys
285→    drawNoteBlocks(true);  // black keys
286→
287→    // Playhead (white line at bottom of waterfall)
288→    ctx.strokeStyle = 'rgba(255, 255, 255, 0.6)';
289→    ctx.lineWidth = 1.5;
290→    ctx.beginPath();
291→    ctx.moveTo(0, waterfallH - 1);
292→    ctx.lineTo(W, waterfallH - 1);
293→    ctx.stroke();
294→
295→    // Fade gradient at top 10%
296→    const fadeH = waterfallH * 0.1;
297→    const fadeGrad = ctx.createLinearGradient(0, 0, 0, fadeH);
298→    fadeGrad.addColorStop(0, WATERFALL_BG);
299→    fadeGrad.addColorStop(1, 'rgba(26, 26, 46, 0)');
300→    ctx.fillStyle = fadeGrad;
301→    ctx.fillRect(0, 0, W, fadeH);
302→
303→    // === DYNAMICS STRIP ===
304→    ctx.fillStyle = '#111118';
305→    ctx.fillRect(0, dynamicsY, W, dynamicsH);
306→
307→    // Separator line
308→    ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
309→    ctx.lineWidth = 1;
310→    ctx.beginPath();
311→    ctx.moveTo(0, dynamicsY);
312→    ctx.lineTo(W, dynamicsY);
313→    ctx.stroke();
314→
315→    // Guide lines for dynamics levels
316→    ctx.font = '9px DM Sans, sans-serif';
317→    ctx.textAlign = 'left';
318→    for (const dl of DYNAMICS_LABELS) {
319→      const y = dynamicsY + dynamicsH - (dl.vel / 127) * dynamicsH;
320→      ctx.strokeStyle = dynamicsColorAlpha(dl.vel, 0.28);
321→      ctx.lineWidth = 0.5;
322→      ctx.beginPath();
323→      ctx.moveTo(0, y);
324→      ctx.lineTo(W, y);
325→      ctx.stroke();
326→
327→      ctx.fillStyle = dynamicsColorAlpha(dl.vel, 0.4);
328→      ctx.fillText(dl.label, 3, y - 2);
329→    }
330→
331→    // Velocity bars for active notes — two passes
332→    const drawDynamicsBars = (blackOnly: boolean) => {
333→      for (const [midi, note] of currentNotes) {
334→        const keyInfo = KEY_BY_MIDI.get(midi);
335→        if (!keyInfo) continue;
336→        if (blackOnly !== keyInfo.isBlack) continue;
337→
338→        const barH = (note.velocity / 127) * (dynamicsH - 4);
339→
340→        let barX: number;
341→        let barW: number;
342→        if (keyInfo.isBlack) {
343→          barX = (keyInfo.whiteIndex + 1) * whiteKeyW - blackKeyW / 2;
344→          barW = blackKeyW;
345→        } else {
346→          barX = keyInfo.whiteIndex * whiteKeyW + 1;
347→          barW = whiteKeyW - 2;
348→        }
349→
350→        const color = dynamicsColor(note.velocity);
351→        if (keyInfo.isBlack) {
352→          ctx.globalAlpha = 0.65;
353→        }
354→
355→        ctx.fillStyle = color;
356→        ctx.fillRect(barX, dynamicsY + dynamicsH - barH - 2, barW, barH);
357→
358→        ctx.globalAlpha = 1.0;
359→      }
360→    };
361→
362→    drawDynamicsBars(false);
363→    drawDynamicsBars(true);
364→
365→    ctx.restore();
366→
367→    rafRef.current = requestAnimationFrame(draw);
368→  }, [windowDurationMs, bpm]);
369→
370→  // rAF loop
371→  useEffect(() => {
372→    rafRef.current = requestAnimationFrame(draw);
373→    return () => {
374→      if (rafRef.current) cancelAnimationFrame(rafRef.current);
375→    };
376→  }, [draw]);
377→
378→  // ResizeObserver
379→  useEffect(() => {
380→    const container = containerRef.current;
381→    if (!container) return;
382→
383→    const observer = new ResizeObserver((entries) => {
384→      for (const entry of entries) {
385→        const w = entry.contentRect.width;
386→        const h = Math.max(280, w * 0.45);
387→        sizeRef.current = { w, h };
388→        const canvas = canvasRef.current;
389→        if (canvas) {
390→          const dpr = window.devicePixelRatio || 1;
391→          canvas.width = w * dpr;
392→          canvas.height = h * dpr;
393→          canvas.style.width = `${w}px`;
394→          canvas.style.height = `${h}px`;
395→        }
396→      }
397→    });
398→    observer.observe(container);
399→    return () => observer.disconnect();
400→  }, []);
401→
402→  return (
403→    <div
404→      ref={containerRef}
405→      style={{
406→        width: '100%',
407→        borderRadius: 8,
408→        overflow: 'hidden',
409→        background: WATERFALL_BG,
410→        border: '1px solid rgba(255, 255, 255, 0.08)',
411→      }}
412→    >
413→      <canvas
414→        ref={canvasRef}
415→        style={{
416→          display: 'block',
417→          width: '100%',
418→        }}
419→      />
420→    </div>
421→  );
422→}
