 1→import { NextRequest } from 'next/server';
 2→import WebSocket from 'ws';
 3→
 4→const BRIDGE_URL = process.env.BRIDGE_WS_URL || 'ws://host.docker.internal:3491/ws';
 5→
 6→export const dynamic = 'force-dynamic';
 7→
 8→export async function GET(req: NextRequest) {
 9→  const encoder = new TextEncoder();
10→  let ws: WebSocket | null = null;
11→  let closed = false;
12→
13→  const stream = new ReadableStream({
14→    start(controller) {
15→      function send(event: string, data: string) {
16→        if (closed) return;
17→        try {
18→          controller.enqueue(encoder.encode(`event: ${event}\ndata: ${data}\n\n`));
19→        } catch {
20→          cleanup();
21→        }
22→      }
23→
24→      function cleanup() {
25→        if (closed) return;
26→        closed = true;
27→        if (ws) {
28→          ws.removeAllListeners();
29→          ws.close();
30→          ws = null;
31→        }
32→        try { controller.close(); } catch {}
33→      }
34→
35→      // Connect to bridge WebSocket server-side
36→      ws = new WebSocket(BRIDGE_URL);
37→
38→      ws.on('open', () => {
39→        send('connected', JSON.stringify({ connected: true }));
40→      });
41→
42→      ws.on('message', (data) => {
43→        try {
44→          const msg = JSON.parse(data.toString());
45→          send(msg.type, data.toString());
46→        } catch {
47→          // skip malformed
48→        }
49→      });
50→
51→      ws.on('close', () => {
52→        send('disconnected', JSON.stringify({ connected: false }));
53→        cleanup();
54→      });
55→
56→      ws.on('error', () => {
57→        send('error', JSON.stringify({ error: 'Bridge connection failed' }));
58→        cleanup();
59→      });
60→
61→      // Send keepalive every 15s to prevent proxy/browser timeout
62→      const keepalive = setInterval(() => {
63→        if (closed) { clearInterval(keepalive); return; }
64→        send('keepalive', JSON.stringify({ ts: Date.now() }));
65→      }, 15000);
66→
67→      // Cleanup when client disconnects
68→      req.signal.addEventListener('abort', () => {
69→        clearInterval(keepalive);
70→        cleanup();
71→      });
72→    },
73→  });
74→
75→  return new Response(stream, {
76→    headers: {
77→      'Content-Type': 'text/event-stream',
78→      'Cache-Control': 'no-cache, no-transform',
79→      'Connection': 'keep-alive',
80→      'X-Accel-Buffering': 'no',
81→    },
82→  });
83→}
