  1→import WebSocket from 'ws';
  2→import { PlayerInfo, QueueEntry, PlayerStatusMessage, SessionWarningMessage } from './types';
  3→
  4→const SESSION_TIMEOUT_MS = 15 * 60 * 1000; // 15 minutes
  5→const WARNING_BEFORE_MS = 60 * 1000; // 60-second warning
  6→
  7→interface ActivePlayer extends PlayerInfo {
  8→  ws: WebSocket | null; // null for desktop (upstream) players
  9→}
 10→
 11→export class PlayerManager {
 12→  private currentPlayer: ActivePlayer | null = null;
 13→  private playQueue: (QueueEntry & { ws: WebSocket })[] = [];
 14→  private sessionTimer: ReturnType<typeof setTimeout> | null = null;
 15→  private warningTimer: ReturnType<typeof setTimeout> | null = null;
 16→  private onBroadcastStatus: ((msg: PlayerStatusMessage) => void) | null = null;
 17→  private onSessionEnd: ((player: PlayerInfo, durationMs: number) => void) | null = null;
 18→
 19→  constructor(
 20→    onBroadcastStatus: (msg: PlayerStatusMessage) => void,
 21→    onSessionEnd?: (player: PlayerInfo, durationMs: number) => void,
 22→  ) {
 23→    this.onBroadcastStatus = onBroadcastStatus;
 24→    this.onSessionEnd = onSessionEnd ?? null;
 25→  }
 26→
 27→  /** Desktop (admin) connects — takes priority, pauses any member */
 28→  setDesktopPlayer(): void {
 29→    if (this.currentPlayer?.source === 'member' && this.currentPlayer.ws) {
 30→      // Pause member — put them back at front of queue
 31→      const member = this.currentPlayer;
 32→      this.clearTimers();
 33→      this.playQueue.unshift({
 34→        userId: member.userId,
 35→        displayName: member.displayName,
 36→        avatarUrl: member.avatarUrl,
 37→        requestedAt: member.connectedAt,
 38→        ws: member.ws!,
 39→      });
 40→      this.sendToWs(member.ws!, {
 41→        type: 'sessionWarning',
 42→        message: 'Jay (admin) has taken over. You have been moved to the front of the queue.',
 43→        remainingSeconds: 0,
 44→      });
 45→    }
 46→
 47→    this.currentPlayer = {
 48→      userId: 'admin',
 49→      displayName: 'Jay',
 50→      avatarUrl: null,
 51→      connectedAt: Date.now(),
 52→      source: 'desktop',
 53→      ws: null,
 54→    };
 55→
 56→    this.broadcastPlayerStatus();
 57→  }
 58→
 59→  /** Desktop disconnects — promote next member in queue */
 60→  clearDesktopPlayer(): void {
 61→    if (this.currentPlayer?.source === 'desktop') {
 62→      this.currentPlayer = null;
 63→      this.promoteNext();
 64→    }
 65→  }
 66→
 67→  /** Member requests to play */
 68→  requestPlay(
 69→    userId: string,
 70→    displayName: string,
 71→    avatarUrl: string | null,
 72→    ws: WebSocket,
 73→  ): { playing: boolean; queuePosition: number } {
 74→    // Already playing?
 75→    if (this.currentPlayer?.userId === userId) {
 76→      return { playing: true, queuePosition: 0 };
 77→    }
 78→
 79→    // Already in queue?
 80→    const existingIdx = this.playQueue.findIndex((e) => e.userId === userId);
 81→    if (existingIdx >= 0) {
 82→      return { playing: false, queuePosition: existingIdx + 1 };
 83→    }
 84→
 85→    // No current player and no desktop? Start playing immediately
 86→    if (!this.currentPlayer) {
 87→      this.startMemberSession(userId, displayName, avatarUrl, ws);
 88→      return { playing: true, queuePosition: 0 };
 89→    }
 90→
 91→    // Add to queue
 92→    this.playQueue.push({ userId, displayName, avatarUrl, requestedAt: Date.now(), ws });
 93→    this.broadcastPlayerStatus();
 94→    return { playing: false, queuePosition: this.playQueue.length };
 95→  }
 96→
 97→  /** Member leaves voluntarily (or disconnects) */
 98→  removePlayer(userId: string): void {
 99→    // Remove from queue
100→    const queueIdx = this.playQueue.findIndex((e) => e.userId === userId);
101→    if (queueIdx >= 0) {
102→      this.playQueue.splice(queueIdx, 1);
103→      this.broadcastPlayerStatus();
104→      return;
105→    }
106→
107→    // Currently playing?
108→    if (this.currentPlayer?.userId === userId && this.currentPlayer.source === 'member') {
109→      const duration = Date.now() - this.currentPlayer.connectedAt;
110→      this.onSessionEnd?.(this.currentPlayer, duration);
111→      this.clearTimers();
112→      this.currentPlayer = null;
113→      this.promoteNext();
114→    }
115→  }
116→
117→  /** Handle WebSocket close for a member */
118→  handleMemberDisconnect(ws: WebSocket): void {
119→    // Check queue
120→    const queueIdx = this.playQueue.findIndex((e) => e.ws === ws);
121→    if (queueIdx >= 0) {
122→      this.playQueue.splice(queueIdx, 1);
123→      this.broadcastPlayerStatus();
124→      return;
125→    }
126→
127→    // Check current player
128→    if (this.currentPlayer?.ws === ws && this.currentPlayer.source === 'member') {
129→      const duration = Date.now() - this.currentPlayer.connectedAt;
130→      this.onSessionEnd?.(this.currentPlayer, duration);
131→      this.clearTimers();
132→      this.currentPlayer = null;
133→      this.promoteNext();
134→    }
135→  }
136→
137→  /** Check if a userId is the current active player */
138→  isCurrentPlayer(userId: string): boolean {
139→    return this.currentPlayer?.userId === userId;
140→  }
141→
142→  /** Get current status for HTTP endpoint */
143→  getStatus(forUserId?: string): {
144→    currentPlayer: { userId: string; displayName: string; avatarUrl: string | null; source: string } | null;
145→    queueLength: number;
146→    queuePosition?: number;
147→  } {
148→    const result: ReturnType<PlayerManager['getStatus']> = {
149→      currentPlayer: this.currentPlayer
150→        ? {
151→            userId: this.currentPlayer.userId,
152→            displayName: this.currentPlayer.displayName,
153→            avatarUrl: this.currentPlayer.avatarUrl,
154→            source: this.currentPlayer.source,
155→          }
156→        : null,
157→      queueLength: this.playQueue.length,
158→    };
159→
160→    if (forUserId) {
161→      if (this.currentPlayer?.userId === forUserId) {
162→        result.queuePosition = 0;
163→      } else {
164→        const idx = this.playQueue.findIndex((e) => e.userId === forUserId);
165→        if (idx >= 0) result.queuePosition = idx + 1;
166→      }
167→    }
168→
169→    return result;
170→  }
171→
172→  private startMemberSession(
173→    userId: string,
174→    displayName: string,
175→    avatarUrl: string | null,
176→    ws: WebSocket,
177→  ): void {
178→    this.currentPlayer = {
179→      userId,
180→      displayName,
181→      avatarUrl,
182→      connectedAt: Date.now(),
183→      source: 'member',
184→      ws,
185→    };
186→
187→    // Session warning at 14 minutes
188→    this.warningTimer = setTimeout(() => {
189→      if (this.currentPlayer?.ws && this.currentPlayer.userId === userId) {
190→        this.sendToWs(this.currentPlayer.ws, {
191→          type: 'sessionWarning',
192→          message: 'Your session ends in 60 seconds',
193→          remainingSeconds: 60,
194→        });
195→      }
196→    }, SESSION_TIMEOUT_MS - WARNING_BEFORE_MS);
197→
198→    // Session end at 15 minutes
199→    this.sessionTimer = setTimeout(() => {
200→      if (this.currentPlayer?.userId === userId && this.currentPlayer.source === 'member') {
201→        const duration = Date.now() - this.currentPlayer.connectedAt;
202→        this.onSessionEnd?.(this.currentPlayer, duration);
203→
204→        if (this.currentPlayer.ws) {
205→          this.sendToWs(this.currentPlayer.ws, {
206→            type: 'sessionWarning',
207→            message: 'Session ended — time limit reached',
208→            remainingSeconds: 0,
209→          });
210→          this.currentPlayer.ws.close(1000, 'Session timeout');
211→        }
212→
213→        this.currentPlayer = null;
214→        this.promoteNext();
215→      }
216→    }, SESSION_TIMEOUT_MS);
217→
218→    this.broadcastPlayerStatus();
219→  }
220→
221→  private promoteNext(): void {
222→    if (this.playQueue.length > 0) {
223→      const next = this.playQueue.shift()!;
224→      if (next.ws.readyState === WebSocket.OPEN) {
225→        this.startMemberSession(next.userId, next.displayName, next.avatarUrl, next.ws);
226→      } else {
227→        // WebSocket already closed, try next
228→        this.promoteNext();
229→      }
230→    } else {
231→      this.broadcastPlayerStatus();
232→    }
233→  }
234→
235→  private clearTimers(): void {
236→    if (this.sessionTimer) {
237→      clearTimeout(this.sessionTimer);
238→      this.sessionTimer = null;
239→    }
240→    if (this.warningTimer) {
241→      clearTimeout(this.warningTimer);
242→      this.warningTimer = null;
243→    }
244→  }
245→
246→  private broadcastPlayerStatus(): void {
247→    const msg: PlayerStatusMessage = {
248→      type: 'playerStatus',
249→      player: this.currentPlayer
250→        ? {
251→            userId: this.currentPlayer.userId,
252→            displayName: this.currentPlayer.displayName,
253→            avatarUrl: this.currentPlayer.avatarUrl,
254→          }
255→        : null,
256→      queueLength: this.playQueue.length,
257→      ...(this.currentPlayer ? { source: this.currentPlayer.source } : {}),
258→    };
259→    this.onBroadcastStatus?.(msg);
260→  }
261→
262→  private sendToWs(ws: WebSocket, msg: SessionWarningMessage): void {
263→    if (ws.readyState === WebSocket.OPEN) {
264→      ws.send(JSON.stringify(msg));
265→    }
266→  }
267→}
