              media: {
                data: frameBytes.toString("base64"),
                mimeType: "image/jpeg",
              },
            });
          }
        } catch {}
      }
    });

    ws.on("close", () => {
      console.log(`[${APP_NAME}] Remote camera disconnected from room "${room}"`);
    });
  });

